INSERT INTO questions (id, user_id, is_system, is_khoa_cu, question_type, content_type, level, selection_type, question, passage, passage_translation, general_explanation, skill_category, base_difficulty, tenant_id, is_active, is_deleted, created_at, created_by) VALUES (81100001, NULL, TRUE, FALSE, 'chon_dap_an', 'keigo_baitap_keigo_phan_loai', 'BJT-1', 'single', '丁寧語（Teineigo）の特徴として正しいものはどれですか？
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (81100001, '相手の行動を高める表現', 'Biểu đạt nâng cao hành động của đối phương', FALSE, 1);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (81100001, '自分の行動を低める表現', 'Biểu đạt hạ thấp hành động của bản thân', FALSE, 2);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (81100001, '誰の行動にも関係なく、文体を丁寧にする表現（〜ます/〜です で終わる）', 'Biểu đạt làm câu văn lịch sự bất kể ai hành động — câu kết thúc bằng 〜ます/〜です', TRUE, 3);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (81100001, '目上の人にだけ使う特別な表現', 'Biểu đạt đặc biệt chỉ dùng với người bề trên', FALSE, 4);
INSERT INTO questions (id, user_id, is_system, is_khoa_cu, question_type, content_type, level, selection_type, question, passage, passage_translation, general_explanation, skill_category, base_difficulty, tenant_id, is_active, is_deleted, created_at, created_by) VALUES (81100002, NULL, TRUE, FALSE, 'chon_dap_an', 'keigo_baitap_keigo_phan_loai', 'BJT-1', 'single', '「食べる」の丁寧語は何ですか？
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (81100002, '召し上がる（めしあがる）', '召し上がる (Sonkeigo — ăn kính trọng)', FALSE, 1);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (81100002, 'いただく', 'いただく (Kenjougo — tôi ăn khiêm nhường)', FALSE, 2);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (81100002, '食べます', '食べます (Teineigo — ăn lịch sự)', TRUE, 3);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (81100002, 'お食べする', 'お食べする (không tự nhiên — sai)', FALSE, 4);
INSERT INTO questions (id, user_id, is_system, is_khoa_cu, question_type, content_type, level, selection_type, question, passage, passage_translation, general_explanation, skill_category, base_difficulty, tenant_id, is_active, is_deleted, created_at, created_by) VALUES (81100003, NULL, TRUE, FALSE, 'chon_dap_an', 'keigo_baitap_keigo_phan_loai', 'BJT-1', 'single', '「きれいだ」の丁寧語は何ですか？
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (81100003, 'きれいます', 'きれいます (sai — tính từ な không thêm ます)', FALSE, 1);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (81100003, 'きれいです', 'きれいです (Teineigo — đúng)', TRUE, 2);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (81100003, 'お綺麗になる', 'お綺麗になる (Sonkeigo — dùng khi khen đối phương)', FALSE, 3);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (81100003, 'きれいでございます', 'きれいでございます (Teineigo trang trọng hơn — đúng nhưng không phải cơ bản nhất)', FALSE, 4);
INSERT INTO questions (id, user_id, is_system, is_khoa_cu, question_type, content_type, level, selection_type, question, passage, passage_translation, general_explanation, skill_category, base_difficulty, tenant_id, is_active, is_deleted, created_at, created_by) VALUES (81100004, NULL, TRUE, FALSE, 'chon_dap_an', 'keigo_baitap_keigo_phan_loai', 'BJT-1', 'single', '「お」と「ご」の使い分けについて正しい説明はどれですか？
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (81100004, 'どちらも自由に使ってよい', 'Cả hai đều dùng tự do', FALSE, 1);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (81100004, '「お」は和語（日本固有語）につく、「ご」は漢語（漢字語）につく（原則）', '「お」đứng trước từ Nhật thuần (Wago), 「ご」đứng trước từ gốc Hán (Kango) — nguyên tắc chung', TRUE, 2);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (81100004, '「お」は謙譲語、「ご」は尊敬語', '「お」là Kenjougo, 「ご」là Sonkeigo', FALSE, 3);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (81100004, '「ご」は書き言葉、「お」は話し言葉', '「ご」là văn viết, 「お」là khẩu ngữ', FALSE, 4);
INSERT INTO questions (id, user_id, is_system, is_khoa_cu, question_type, content_type, level, selection_type, question, passage, passage_translation, general_explanation, skill_category, base_difficulty, tenant_id, is_active, is_deleted, created_at, created_by) VALUES (81100005, NULL, TRUE, FALSE, 'chon_dap_an', 'keigo_baitap_keigo_phan_loai', 'BJT-1', 'single', '次の中で「お」または「ご」の使い方が間違っているものはどれですか？
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (81100005, 'お電話（おでんわ）', 'お電話 (điện thoại — đúng, 電話 là Kango nhưng dùng お theo thói quen)', FALSE, 1);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (81100005, 'ご名前（ごなまえ）', 'ご名前 (tên — sai! 名前 là Wago → phải dùng お名前)', TRUE, 2);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (81100005, 'ご住所（ごじゅうしょ）', 'ご住所 (địa chỉ — đúng, 住所 là Kango)', FALSE, 3);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (81100005, 'お時間（おじかん）', 'お時間 (thời gian — đúng, thường dùng với お)', FALSE, 4);
INSERT INTO questions (id, user_id, is_system, is_khoa_cu, question_type, content_type, level, selection_type, question, passage, passage_translation, general_explanation, skill_category, base_difficulty, tenant_id, is_active, is_deleted, created_at, created_by) VALUES (81100006, NULL, TRUE, FALSE, 'chon_dap_an', 'keigo_baitap_keigo_phan_loai', 'BJT-1', 'single', '「ない」の丁寧語は何ですか？（動詞の否定形）
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (81100006, '〜ないです', '〜ないです (lịch sự, thông dụng trong hội thoại)', FALSE, 1);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (81100006, '〜ません', '〜ません (Teineigo chuẩn — lịch sự hơn ないです)', FALSE, 2);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (81100006, '〜ないでしょう', '〜ないでしょう (phỏng đoán phủ định)', FALSE, 3);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (81100006, 'A と B の両方が丁寧語として正しい', 'Cả A và B đều là Teineigo đúng', TRUE, 4);
INSERT INTO questions (id, user_id, is_system, is_khoa_cu, question_type, content_type, level, selection_type, question, passage, passage_translation, general_explanation, skill_category, base_difficulty, tenant_id, is_active, is_deleted, created_at, created_by) VALUES (81100007, NULL, TRUE, FALSE, 'chon_dap_an', 'keigo_baitap_keigo_phan_loai', 'BJT-1', 'single', '「行く」の丁寧語の過去形と過去否定形を正しく選んでください。
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (81100007, '行きました / 行きませんでした', '行きました / 行きませんでした (Teineigo quá khứ / phủ định quá khứ — đúng)', TRUE, 1);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (81100007, '行きました / 行かなかったです', '行きました / 行かなかったです (phủ định quá khứ — cũng được nhưng ít trang trọng hơn)', FALSE, 2);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (81100007, '行きました / 行きません', '行きました (quá khứ) / 行きません (phủ định hiện tại — sai)', FALSE, 3);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (81100007, '行ったです / 行かないでした', '行ったです / 行かないでした (sai ngữ pháp)', FALSE, 4);
INSERT INTO questions (id, user_id, is_system, is_khoa_cu, question_type, content_type, level, selection_type, question, passage, passage_translation, general_explanation, skill_category, base_difficulty, tenant_id, is_active, is_deleted, created_at, created_by) VALUES (81100008, NULL, TRUE, FALSE, 'chon_dap_an', 'keigo_baitap_keigo_phan_loai', 'BJT-1', 'single', '次の「お」/「ご」がついた言葉のうち、Teineigo（丁寧語）として正しく使われているものはどれですか？
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (81100008, 'お茶（おちゃ）', 'お茶 (trà) — tiền tố お làm từ lịch sự hơn', FALSE, 1);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (81100008, 'ご飯（ごはん）', 'ご飯 (cơm/bữa ăn) — tiền tố ご cố định', FALSE, 2);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (81100008, 'お手洗い（おてあらい）', 'お手洗い (nhà vệ sinh) — dùng tiền tố お', FALSE, 3);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (81100008, '上記の全て', 'Tất cả những từ trên', TRUE, 4);
INSERT INTO questions (id, user_id, is_system, is_khoa_cu, question_type, content_type, level, selection_type, question, passage, passage_translation, general_explanation, skill_category, base_difficulty, tenant_id, is_active, is_deleted, created_at, created_by) VALUES (81100009, NULL, TRUE, FALSE, 'chon_dap_an', 'keigo_baitap_keigo_phan_loai', 'BJT-1', 'single', '「山田部長は出張に行かれました」— この文の敬語の種類は？
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (81100009, '謙譲語（Kenjougo）', 'Kenjougo (Khiêm nhường ngữ)', FALSE, 1);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (81100009, '丁寧語（Teineigo）のみ', 'Chỉ Teineigo (Lịch sự ngữ)', FALSE, 2);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (81100009, '尊敬語（Sonkeigo）— 〜れる形', 'Sonkeigo (Tôn kính ngữ) — dùng cấu trúc 〜れる', FALSE, 3);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (81100009, '尊敬語＋丁寧語の組み合わせ', 'Kết hợp Sonkeigo + Teineigo', TRUE, 4);
INSERT INTO questions (id, user_id, is_system, is_khoa_cu, question_type, content_type, level, selection_type, question, passage, passage_translation, general_explanation, skill_category, base_difficulty, tenant_id, is_active, is_deleted, created_at, created_by) VALUES (81100010, NULL, TRUE, FALSE, 'chon_dap_an', 'keigo_baitap_keigo_phan_loai', 'BJT-1', 'single', '「何時ですか？」より丁寧な聞き方はどれですか？
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (81100010, '何時？', '何時？ (thô, thân mật — ít lịch sự hơn)', FALSE, 1);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (81100010, '今、何時でしょうか？', 'Bây giờ là mấy giờ ạ? (でしょうか — lịch sự hơn)', FALSE, 2);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (81100010, '今、何時でございますか？', 'Bây giờ là mấy giờ ạ? (でございますか — trang trọng nhất)', FALSE, 3);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (81100010, 'B と C の両方が「何時ですか」より丁寧', 'Cả B và C đều lịch sự hơn 何時ですか', TRUE, 4);
INSERT INTO questions (id, user_id, is_system, is_khoa_cu, question_type, content_type, level, selection_type, question, passage, passage_translation, general_explanation, skill_category, base_difficulty, tenant_id, is_active, is_deleted, created_at, created_by) VALUES (81100011, NULL, TRUE, FALSE, 'chon_dap_an', 'keigo_baitap_keigo_phan_loai', 'BJT-2', 'single', '「です」と「でございます」の違いとして正しいのはどれですか？
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (81100011, '意味は全く同じで、どちらも同じ場面で使える', 'Hoàn toàn giống nhau, dùng được trong mọi tình huống', FALSE, 1);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (81100011, '「でございます」は「です」の丁寧語で、より格式が高い', '「でございます」là Teineigo của です — trang trọng hơn một bậc', TRUE, 2);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (81100011, '「でございます」は謙譲語なので、自分のことにしか使えない', '「でございます」là Kenjougo nên chỉ dùng về bản thân', FALSE, 3);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (81100011, '「でございます」は尊敬語なので、相手のことにしか使えない', '「でございます」là Sonkeigo nên chỉ dùng về đối phương', FALSE, 4);
INSERT INTO questions (id, user_id, is_system, is_khoa_cu, question_type, content_type, level, selection_type, question, passage, passage_translation, general_explanation, skill_category, base_difficulty, tenant_id, is_active, is_deleted, created_at, created_by) VALUES (81100012, NULL, TRUE, FALSE, 'chon_dap_an', 'keigo_baitap_keigo_phan_loai', 'BJT-2', 'single', '「ございます」と「あります」の使い分けとして正しいのはどれですか？
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (81100012, '「ございます」は生き物に、「あります」は物に使う', '「ございます」cho sinh vật, 「あります」cho đồ vật', FALSE, 1);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (81100012, '「ございます」はより丁寧なあります。主に物事の存在や状況に使う', '「ございます」là dạng trang trọng của あります — dùng cho sự tồn tại của vật/tình huống', TRUE, 2);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (81100012, '意味は同じで使い分けは不要', 'Hoàn toàn giống nhau, không cần phân biệt', FALSE, 3);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (81100012, '「ございます」は謙譲語、「あります」は普通語', '「ございます」là Kenjougo, 「あります」là thông thường', FALSE, 4);
INSERT INTO questions (id, user_id, is_system, is_khoa_cu, question_type, content_type, level, selection_type, question, passage, passage_translation, general_explanation, skill_category, base_difficulty, tenant_id, is_active, is_deleted, created_at, created_by) VALUES (81100013, NULL, TRUE, FALSE, 'chon_dap_an', 'keigo_baitap_keigo_phan_loai', 'BJT-2', 'single', '「でございます」の否定形と過去形を正しく選んでください。
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (81100013, '否定：ではございません / 過去：でございました', 'Phủ định: ではございません / Quá khứ: でございました — đúng', TRUE, 1);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (81100013, '否定：でございません / 過去：でございましたん', 'Phủ định: でございません / Quá khứ: でございましたん — sai', FALSE, 2);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (81100013, '否定：ではないでございます / 過去：でありました', 'Phủ định: ではないでございます / Quá khứ: でありました — không chuẩn', FALSE, 3);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (81100013, '否定：ではございません / 過去：でございましたでした', 'Phủ định: ではございません / Quá khứ: でございましたでした — sai', FALSE, 4);
INSERT INTO questions (id, user_id, is_system, is_khoa_cu, question_type, content_type, level, selection_type, question, passage, passage_translation, general_explanation, skill_category, base_difficulty, tenant_id, is_active, is_deleted, created_at, created_by) VALUES (81100014, NULL, TRUE, FALSE, 'chon_dap_an', 'keigo_baitap_keigo_phan_loai', 'BJT-2', 'single', '「〜でしょうか」の機能として正しいのはどれですか？
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (81100014, '推量（〜だろう）の丁寧語として、または丁寧な疑問文を作る', 'Teineigo của 〜だろう (phỏng đoán), hoặc tạo câu hỏi lịch sự', TRUE, 1);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (81100014, '過去の出来事を推量する時だけに使う', 'Chỉ dùng khi phỏng đoán sự việc trong quá khứ', FALSE, 2);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (81100014, '「ですか」と全く同じで、置き換え可能', 'Hoàn toàn giống 「ですか」, có thể thay thế hoàn toàn', FALSE, 3);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (81100014, '命令や依頼を表す', 'Biểu đạt mệnh lệnh hoặc yêu cầu', FALSE, 4);
INSERT INTO questions (id, user_id, is_system, is_khoa_cu, question_type, content_type, level, selection_type, question, passage, passage_translation, general_explanation, skill_category, base_difficulty, tenant_id, is_active, is_deleted, created_at, created_by) VALUES (81100015, NULL, TRUE, FALSE, 'chon_dap_an', 'keigo_baitap_keigo_phan_loai', 'BJT-2', 'single', '受付で来客に「ご用件は何ですか？」より丁寧に聞く表現はどれですか？
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (81100015, '何の用ですか？', 'Anh/chị đến có việc gì? (thô — thiếu tiền tố ご)', FALSE, 1);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (81100015, 'ご用件は何でしょうか？', 'Không biết quý vị có việc gì ạ? (でしょうか — lịch sự hơn)', FALSE, 2);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (81100015, '本日はどのようなご用件でいらっしゃいますか？', 'Hôm nay quý vị đến có việc gì ạ? (kết hợp Teineigo + Sonkeigo — trang trọng nhất)', FALSE, 3);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (81100015, 'B と C の両方が「ご用件は何ですか」より丁寧', 'Cả B và C đều lịch sự hơn câu gốc', TRUE, 4);
INSERT INTO questions (id, user_id, is_system, is_khoa_cu, question_type, content_type, level, selection_type, question, passage, passage_translation, general_explanation, skill_category, base_difficulty, tenant_id, is_active, is_deleted, created_at, created_by) VALUES (81100016, NULL, TRUE, FALSE, 'chon_dap_an', 'keigo_baitap_keigo_phan_loai', 'BJT-2', 'single', '「〜てもいいですか？」を最も丁寧な Teineigo に直すと？
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (81100016, '〜てもいいでしょうか？', '〜てもいいでしょうか？ (でしょうか — lịch sự hơn)', FALSE, 1);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (81100016, '〜てもよろしいでしょうか？', '〜てもよろしいでしょうか？ (よろしい + でしょうか — trang trọng nhất)', FALSE, 2);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (81100016, '〜てもよろしゅうございますか？', '〜てもよろしゅうございますか？ (cổ điển, cực trang trọng — ít dùng ngày nay)', FALSE, 3);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (81100016, 'B が最も自然でビジネス的', 'B tự nhiên và kinh doanh nhất trong thực tế hiện đại', TRUE, 4);
INSERT INTO questions (id, user_id, is_system, is_khoa_cu, question_type, content_type, level, selection_type, question, passage, passage_translation, general_explanation, skill_category, base_difficulty, tenant_id, is_active, is_deleted, created_at, created_by) VALUES (81100017, NULL, TRUE, FALSE, 'chon_dap_an', 'keigo_baitap_keigo_phan_loai', 'BJT-2', 'single', 'ビジネス場面での電話応対として、最も適切な電話の出方はどれですか？
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (81100017, '「はい、田中です。」', '「はい、田中です。」(thông thường — thiếu trang trọng)', FALSE, 1);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (81100017, '「はい、〇〇株式会社でございます。」', '「はい、〇〇株式会社でございます。」(でございます — chuẩn)', FALSE, 2);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (81100017, '「もしもし、〇〇会社です。」', '「もしもし、〇〇会社です。」(もしもし không dùng trong kinh doanh — sai)', FALSE, 3);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (81100017, '「はい、〇〇株式会社の田中でございます。」', '「はい、〇〇株式会社の田中でございます。」(tên + でございます — trang trọng nhất)', TRUE, 4);
INSERT INTO questions (id, user_id, is_system, is_khoa_cu, question_type, content_type, level, selection_type, question, passage, passage_translation, general_explanation, skill_category, base_difficulty, tenant_id, is_active, is_deleted, created_at, created_by) VALUES (81100018, NULL, TRUE, FALSE, 'chon_dap_an', 'keigo_baitap_keigo_phan_loai', 'BJT-2', 'single', '次の文でお/ごの使い方が正しいものはどれですか？
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (81100018, 'ご結婚おめでとうございます。', 'Chúc mừng ngài kết hôn. (ご結婚 — đúng, 結婚 là Kango)', FALSE, 1);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (81100018, 'お結婚おめでとうございます。', 'Chúc mừng ngài kết hôn. (お結婚 — sai, 結婚 là Kango phải dùng ご)', FALSE, 2);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (81100018, 'ご誕生日おめでとうございます。', 'Chúc mừng sinh nhật ngài. (ご誕生日 — đúng theo Kango, nhưng おも phổ biến hơn)', FALSE, 3);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (81100018, 'A と C の両方が正しい', 'Cả A và C đều đúng', TRUE, 4);
INSERT INTO questions (id, user_id, is_system, is_khoa_cu, question_type, content_type, level, selection_type, question, passage, passage_translation, general_explanation, skill_category, base_difficulty, tenant_id, is_active, is_deleted, created_at, created_by) VALUES (81100019, NULL, TRUE, FALSE, 'chon_dap_an', 'keigo_baitap_keigo_phan_loai', 'BJT-2', 'single', 'お客様に「会議室は3階です」を最も丁寧に伝えると？
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (81100019, '会議室は3階です。', 'Phòng họp ở tầng 3. (Teineigo cơ bản)', FALSE, 1);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (81100019, '会議室は3階でございます。', 'Phòng họp ở tầng 3 ạ. (でございます — trang trọng hơn)', FALSE, 2);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (81100019, '会議室は3階となっております。', 'Phòng họp là tầng 3 ạ. (となっております — Kenjougo + Teineigo)', FALSE, 3);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (81100019, 'B と C の両方がビジネス的に適切', 'Cả B và C đều phù hợp trong kinh doanh', TRUE, 4);
INSERT INTO questions (id, user_id, is_system, is_khoa_cu, question_type, content_type, level, selection_type, question, passage, passage_translation, general_explanation, skill_category, base_difficulty, tenant_id, is_active, is_deleted, created_at, created_by) VALUES (81100020, NULL, TRUE, FALSE, 'chon_dap_an', 'keigo_baitap_keigo_phan_loai', 'BJT-2', 'single', 'メールの結びの言葉として最も一般的な丁寧語表現はどれですか？
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (81100020, 'バイバイ。', 'Bye bye. (không phù hợp)', FALSE, 1);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (81100020, 'では、また。', 'Thế nhé, hẹn gặp lại. (thân mật — không phù hợp email công việc)', FALSE, 2);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (81100020, '以上、よろしくお願いいたします。', 'Trên đây là toàn bộ, kính mong sự hợp tác. (Kenjougo + Teineigo — chuẩn)', FALSE, 3);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (81100020, 'どうぞよろしくお願い申し上げます。', 'Kính nhờ quý vị. (Kenjougo trang trọng — chuẩn)', TRUE, 4);
INSERT INTO questions (id, user_id, is_system, is_khoa_cu, question_type, content_type, level, selection_type, question, passage, passage_translation, general_explanation, skill_category, base_difficulty, tenant_id, is_active, is_deleted, created_at, created_by) VALUES (81100021, NULL, TRUE, FALSE, 'chon_dap_an', 'keigo_baitap_keigo_phan_loai', 'BJT-3', 'single', 'お客様が到着した時の一連の応対で、敬語の使い方が最も正確な流れはどれですか？
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (81100021, '①「いらっしゃいませ」②「お名前をいただけますか」③「少々お待ちください」', '① Kính chào ② Tôi có thể nhận tên của ngài không? (いただく sai ở đây) ③ Xin chờ chút', FALSE, 1);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (81100021, '①「いらっしゃいませ」②「お名前をお聞かせいただけますでしょうか」③「少々お待ちくださいませ」', '① Kính chào ② Cho tôi biết tên của ngài không ạ? ③ Xin vui lòng chờ chút ạ', TRUE, 2);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (81100021, '①「こんにちは」②「名前は何ですか」③「ちょっと待って」', '① Chào ② Tên bạn là gì? ③ Chờ tí (thô — hoàn toàn không phù hợp)', FALSE, 3);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (81100021, '①「いらっしゃいませ」②「お名前を教えてもらえますか」③「お待ちください」', '① Kính chào ② Bạn có thể cho biết tên không? ③ Xin chờ (câu ② thiếu trang trọng)', FALSE, 4);
INSERT INTO questions (id, user_id, is_system, is_khoa_cu, question_type, content_type, level, selection_type, question, passage, passage_translation, general_explanation, skill_category, base_difficulty, tenant_id, is_active, is_deleted, created_at, created_by) VALUES (81100022, NULL, TRUE, FALSE, 'chon_dap_an', 'keigo_baitap_keigo_phan_loai', 'BJT-3', 'single', '「すみません」「申し訳ありません」「申し訳ございません」を丁寧さの低い順に並べてください。
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (81100022, 'すみません→申し訳ありません→申し訳ございません', 'すみません (thông thường) → 申し訳ありません (Teineigo) → 申し訳ございません (Teineigo trang trọng nhất)', TRUE, 1);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (81100022, '申し訳ございません→申し訳ありません→すみません', 'Ngược lại', FALSE, 2);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (81100022, '申し訳ありません→すみません→申し訳ございません', 'Thứ tự khác', FALSE, 3);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (81100022, '全て同じ丁寧さ', 'Tất cả có cùng mức lịch sự', FALSE, 4);
INSERT INTO questions (id, user_id, is_system, is_khoa_cu, question_type, content_type, level, selection_type, question, passage, passage_translation, general_explanation, skill_category, base_difficulty, tenant_id, is_active, is_deleted, created_at, created_by) VALUES (81100023, NULL, TRUE, FALSE, 'chon_dap_an', 'keigo_baitap_keigo_phan_loai', 'BJT-3', 'single', '初めてメールを送る相手への書き出しとして最も適切なものはどれですか？
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (81100023, 'いつもお世話になっております。', 'Cảm ơn sự quan tâm của quý vị. (Dùng khi ĐÃ có quan hệ — sai khi lần đầu)', FALSE, 1);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (81100023, '突然のご連絡、失礼いたします。〇〇社の田中と申します。', 'Xin lỗi vì liên hệ đột ngột. Tôi là Tanaka, công ty 〇〇 ạ. (Kenjougo — đúng khi lần đầu)', TRUE, 2);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (81100023, 'はじめまして。田中です。よろしく。', 'Rất vui được gặp. Tôi là Tanaka. Nhờ bạn nhé. (quá thân mật)', FALSE, 3);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (81100023, 'ご無沙汰しております。', 'Lâu ngày không liên lạc ạ. (Dùng khi đã quen nhưng lâu không liên lạc — sai khi lần đầu)', FALSE, 4);
INSERT INTO questions (id, user_id, is_system, is_khoa_cu, question_type, content_type, level, selection_type, question, passage, passage_translation, general_explanation, skill_category, base_difficulty, tenant_id, is_active, is_deleted, created_at, created_by) VALUES (81100024, NULL, TRUE, FALSE, 'chon_dap_an', 'keigo_baitap_keigo_phan_loai', 'BJT-3', 'single', '「会議は3時から始まります」をお客様に伝える最も丁寧な表現はどれですか？
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (81100024, '会議は3時から始まります。', 'Cuộc họp bắt đầu từ 3 giờ. (Teineigo cơ bản)', FALSE, 1);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (81100024, '会議は3時からでございます。', 'Cuộc họp là từ 3 giờ ạ. (でございます — lịch sự hơn)', FALSE, 2);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (81100024, '会議は3時よりご開催となっております。', 'Cuộc họp được tổ chức từ 3 giờ ạ. (ご開催 + となっております — trang trọng nhất)', FALSE, 3);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (81100024, 'B と C の両方が A より丁寧', 'Cả B và C đều lịch sự hơn A', TRUE, 4);
INSERT INTO questions (id, user_id, is_system, is_khoa_cu, question_type, content_type, level, selection_type, question, passage, passage_translation, general_explanation, skill_category, base_difficulty, tenant_id, is_active, is_deleted, created_at, created_by) VALUES (81100025, NULL, TRUE, FALSE, 'chon_dap_an', 'keigo_baitap_keigo_phan_loai', 'BJT-3', 'single', '電話で「担当の田中は今、席にいません」を丁寧に伝えると？（田中はUchi）
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (81100025, '田中はいません。', 'Tanaka không có. (thô)', FALSE, 1);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (81100025, '田中はただいま席を外しております。', 'Tanaka hiện đang vắng chỗ ạ. (Kenjougo + Teineigo — chuẩn)', FALSE, 2);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (81100025, '田中はただいま離席中でございます。', 'Tanaka hiện đang vắng chỗ ạ. (でございます — trang trọng hơn)', FALSE, 3);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (81100025, 'B と C の両方が適切', 'Cả B và C đều phù hợp', TRUE, 4);
INSERT INTO questions (id, user_id, is_system, is_khoa_cu, question_type, content_type, level, selection_type, question, passage, passage_translation, general_explanation, skill_category, base_difficulty, tenant_id, is_active, is_deleted, created_at, created_by) VALUES (81100026, NULL, TRUE, FALSE, 'chon_dap_an', 'keigo_baitap_keigo_phan_loai', 'BJT-3', 'single', '「〜と思います」「〜と存じます」「〜かと存じます」を丁寧さの低い順に並べてください。
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (81100026, '〜と思います → 〜と存じます → 〜かと存じます', 'と思います (Teineigo) → と存じます (Kenjougo) → かと存じます (Kenjougo + phỏng đoán nhẹ = lịch sự nhất)', TRUE, 1);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (81100026, '〜かと存じます → 〜と存じます → 〜と思います', 'Ngược lại hoàn toàn', FALSE, 2);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (81100026, '〜と存じます → 〜と思います → 〜かと存じます', 'Thứ tự khác', FALSE, 3);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (81100026, '全て同じ', 'Tất cả giống nhau', FALSE, 4);
INSERT INTO questions (id, user_id, is_system, is_khoa_cu, question_type, content_type, level, selection_type, question, passage, passage_translation, general_explanation, skill_category, base_difficulty, tenant_id, is_active, is_deleted, created_at, created_by) VALUES (81100027, NULL, TRUE, FALSE, 'chon_dap_an', 'keigo_baitap_keigo_phan_loai', 'BJT-3', 'single', '電話で担当者に取り次ぐ時、正しい表現の組み合わせはどれですか？
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (81100027, '①「少々お待ちくださいませ」②「田中さん、〇〇様からお電話です」', '① Xin đợi chút ạ ② Anh Tanaka, có điện thoại của ông/bà 〇〇 ạ', FALSE, 1);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (81100027, '①「ちょっと待って」②「電話だよ」', '① Chờ chút ② Có điện thoại đó (thô — không phù hợp cả hai)', FALSE, 2);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (81100027, '①「少々お待ちいただけますでしょうか」②「田中さん、〇〇様よりお電話が入っております」', '① Xin phép chờ chút ạ ② Anh Tanaka, có điện thoại từ ông/bà 〇〇 ạ (trang trọng hơn A)', FALSE, 3);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (81100027, 'A と C の両方が状況に応じて使える', 'Cả A và C đều dùng được tùy mức trang trọng', TRUE, 4);
INSERT INTO questions (id, user_id, is_system, is_khoa_cu, question_type, content_type, level, selection_type, question, passage, passage_translation, general_explanation, skill_category, base_difficulty, tenant_id, is_active, is_deleted, created_at, created_by) VALUES (81100028, NULL, TRUE, FALSE, 'chon_dap_an', 'keigo_baitap_keigo_phan_loai', 'BJT-3', 'single', '会議の開始を告げる際、最も適切なビジネス表現はどれですか？
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (81100028, 'じゃあ、始めましょう。', 'Thì bắt đầu thôi nào. (thân mật — không phù hợp họp chính thức)', FALSE, 1);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (81100028, 'それでは、ただいまより会議を始めます。', 'Vậy thì, bây giờ chúng ta bắt đầu cuộc họp. (Teineigo — phổ biến)', FALSE, 2);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (81100028, 'それでは、定刻となりましたので、ただいまより会議を始めさせていただきます。', 'Vậy thì, đã đến giờ quy định, xin phép bắt đầu cuộc họp ạ. (đầy đủ nhất)', FALSE, 3);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (81100028, 'B と C の両方が使える', 'Cả B và C đều dùng được', TRUE, 4);
INSERT INTO questions (id, user_id, is_system, is_khoa_cu, question_type, content_type, level, selection_type, question, passage, passage_translation, general_explanation, skill_category, base_difficulty, tenant_id, is_active, is_deleted, created_at, created_by) VALUES (81100029, NULL, TRUE, FALSE, 'chon_dap_an', 'keigo_baitap_keigo_phan_loai', 'BJT-3', 'single', '社内の同僚に話す時と、お客様に話す時で、使う敬語レベルが違います。正しい例はどれですか？
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (81100029, '社内：「田中部長はいらっしゃいますか」/ 社外：「田中はおりますか」', 'Nội bộ: ''Trưởng phòng Tanaka có không?'' / Bên ngoài: ''Tanaka có không?'' (ngược — SAI)', FALSE, 1);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (81100029, '社内：「田中部長はいますか」/ 社外（お客様に）：「田中はただいまおります」', 'Nội bộ: ''Trưởng phòng Tanaka có không?'' / Với khách: ''Tanaka đang có mặt ạ'' (đúng)', TRUE, 2);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (81100029, '社内も社外も同じ敬語を使う', 'Trong và ngoài dùng kính ngữ giống nhau', FALSE, 3);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (81100029, '社外ではいつもSonkeigoだけ使う', 'Khi nói với bên ngoài luôn chỉ dùng Sonkeigo', FALSE, 4);
INSERT INTO questions (id, user_id, is_system, is_khoa_cu, question_type, content_type, level, selection_type, question, passage, passage_translation, general_explanation, skill_category, base_difficulty, tenant_id, is_active, is_deleted, created_at, created_by) VALUES (81100030, NULL, TRUE, FALSE, 'chon_dap_an', 'keigo_baitap_keigo_phan_loai', 'BJT-3', 'single', 'お客様との商談が終わった後、お見送りする時の言葉として最も適切なものはどれですか？
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (81100030, 'バイバイ。またね。', 'Bye bye. Gặp lại nhé. (hoàn toàn không phù hợp)', FALSE, 1);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (81100030, 'ありがとうございました。お気をつけてお帰りください。', 'Cảm ơn ạ. Mời ngài về bình an. (Teineigo + Sonkeigo — chuẩn)', FALSE, 2);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (81100030, '本日はご足労いただき、誠にありがとうございました。どうぞお気をつけてお帰りくださいませ。', 'Cảm ơn ngài đã không quản đường xá hôm nay ạ. Kính mời ngài về bình an. (trang trọng nhất)', FALSE, 3);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (81100030, 'B と C の両方が状況に応じて使える', 'Cả B và C đều dùng được tùy mức quan trọng của khách', TRUE, 4);
INSERT INTO questions (id, user_id, is_system, is_khoa_cu, question_type, content_type, level, selection_type, question, passage, passage_translation, general_explanation, skill_category, base_difficulty, tenant_id, is_active, is_deleted, created_at, created_by) VALUES (81100031, NULL, TRUE, FALSE, 'chon_dap_an', 'keigo_baitap_keigo_phan_loai', 'BJT-4', 'single', '次の文の中で「でございます」の使い方が間違っているものはどれですか？
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (81100031, 'こちらが会議室でございます。', 'Đây là phòng họp ạ. (danh từ + でございます — đúng)', FALSE, 1);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (81100031, 'お客様がいらっしゃいますでございます。', 'Khách hàng đang ở đây ạ. (いらっしゃいます + でございます = kép — sai!)', TRUE, 2);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (81100031, '資料はこちらでございます。', 'Tài liệu là ở đây ạ. (đúng)', FALSE, 3);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (81100031, '田中でございます。', 'Tôi là Tanaka ạ. (tên + でございます — đúng)', FALSE, 4);
INSERT INTO questions (id, user_id, is_system, is_khoa_cu, question_type, content_type, level, selection_type, question, passage, passage_translation, general_explanation, skill_category, base_difficulty, tenant_id, is_active, is_deleted, created_at, created_by) VALUES (81100032, NULL, TRUE, FALSE, 'chon_dap_an', 'keigo_baitap_keigo_phan_loai', 'BJT-4', 'single', '「ご確認いただけますと幸いでございます」の敬語分析として正しいのはどれですか？
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (81100032, '全体が尊敬語', 'Toàn bộ là Sonkeigo', FALSE, 1);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (81100032, '「ご確認」は丁寧語、「いただけます」は謙譲語、「でございます」は丁寧語', '「ご確認」= Teineigo, 「いただけます」= Kenjougo, 「でございます」= Teineigo', FALSE, 2);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (81100032, '「ご確認」は尊敬語（相手の行動を高める）、「いただけます」は謙譲語（自分が受ける）、「でございます」は丁寧語', '「ご確認」= Sonkeigo (nâng hành động xác nhận của đối phương), 「いただけます」= Kenjougo (mình được nhận), 「でございます」= Teineigo', TRUE, 3);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (81100032, '全体が謙譲語', 'Toàn bộ là Kenjougo', FALSE, 4);
INSERT INTO questions (id, user_id, is_system, is_khoa_cu, question_type, content_type, level, selection_type, question, passage, passage_translation, general_explanation, skill_category, base_difficulty, tenant_id, is_active, is_deleted, created_at, created_by) VALUES (81100033, NULL, TRUE, FALSE, 'chon_dap_an', 'keigo_baitap_keigo_phan_loai', 'BJT-4', 'single', '次の文でお/ごの使い方に問題があるものはどれですか？
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (81100033, 'お荷物をお預かりいたします。', 'Tôi xin giữ hành lý giúp quý vị. (お荷物 + お預かり — đúng)', FALSE, 1);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (81100033, 'ご挨拶をお申し上げます。', 'Tôi xin kính chào. (ご挨拶 + お申し上げ — sai kết hợp)', TRUE, 2);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (81100033, 'お料理をご用意いたしました。', 'Chúng tôi đã chuẩn bị món ăn. (お料理 + ご用意いたす — đúng)', FALSE, 3);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (81100033, 'ご連絡をお待ちしております。', 'Tôi đang chờ liên hệ của quý vị. (ご連絡 + お待ちする — đúng)', FALSE, 4);
INSERT INTO questions (id, user_id, is_system, is_khoa_cu, question_type, content_type, level, selection_type, question, passage, passage_translation, general_explanation, skill_category, base_difficulty, tenant_id, is_active, is_deleted, created_at, created_by) VALUES (81100034, NULL, TRUE, FALSE, 'chon_dap_an', 'keigo_baitap_keigo_phan_loai', 'BJT-4', 'single', '次のうち「ございます」の使い方が最も適切なものはどれですか？
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (81100034, 'お客様がございます。', 'Khách hàng đang ở đây. (ございます cho người — SAI)', FALSE, 1);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (81100034, 'ご不明な点がございましたら、お知らせください。', 'Nếu có điểm nào chưa rõ, mời quý vị cho biết ạ. (ございます cho tình huống — đúng)', FALSE, 2);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (81100034, 'ありがとうございます — ここでの「ございます」は何ですか？', 'ありがとうございます — ございます ở đây là gì?', FALSE, 3);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (81100034, 'B は正しい。C の「ございます」は「ある」の丁寧語として固定表現', 'B đúng. ございます trong C là dạng cố định của ある (→ ありがとうある → ありがとうございます)', TRUE, 4);
INSERT INTO questions (id, user_id, is_system, is_khoa_cu, question_type, content_type, level, selection_type, question, passage, passage_translation, general_explanation, skill_category, base_difficulty, tenant_id, is_active, is_deleted, created_at, created_by) VALUES (81100035, NULL, TRUE, FALSE, 'chon_dap_an', 'keigo_baitap_keigo_phan_loai', 'BJT-4', 'single', '「〜ではございません」「〜ではありません」「〜ではないです」を使い分ける基準として正しいのは？
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (81100035, '全て同じで、使い分けは不要', 'Tất cả giống nhau, không cần phân biệt', FALSE, 1);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (81100035, '丁寧さ：ではないです（普通） < ではありません（丁寧） < ではございません（最丁寧）', 'Mức lịch sự: ではないです (thông thường) < ではありません (lịch sự) < ではございません (trang trọng nhất)', TRUE, 2);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (81100035, '「ではございません」は尊敬語なので、相手のことにしか使えない', '「ではございません」là Sonkeigo, chỉ dùng về đối phương', FALSE, 3);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (81100035, '「ではないです」は文法的に間違い', '「ではないです」sai ngữ pháp', FALSE, 4);
INSERT INTO questions (id, user_id, is_system, is_khoa_cu, question_type, content_type, level, selection_type, question, passage, passage_translation, general_explanation, skill_category, base_difficulty, tenant_id, is_active, is_deleted, created_at, created_by) VALUES (81100036, NULL, TRUE, FALSE, 'chon_dap_an', 'keigo_baitap_keigo_phan_loai', 'BJT-4', 'single', '次のアナウンス文で、最も不自然または間違った表現はどれですか？
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (81100036, '① ご来場いただきまして', '① ご来場いただきまして', FALSE, 1);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (81100036, '③ 開演でございます', '③ 開演でございます', FALSE, 2);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (81100036, '④ 電源をお切りください', '④ 電源をお切りください — お切り là không tự nhiên', FALSE, 3);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (81100036, '⑤ ご遠慮してください', '⑤ ご遠慮してください — sai cấu trúc, phải là ご遠慮ください hoặc ご遠慮いただけますか', TRUE, 4);
INSERT INTO questions (id, user_id, is_system, is_khoa_cu, question_type, content_type, level, selection_type, question, passage, passage_translation, general_explanation, skill_category, base_difficulty, tenant_id, is_active, is_deleted, created_at, created_by) VALUES (81100037, NULL, TRUE, FALSE, 'chon_dap_an', 'keigo_baitap_keigo_phan_loai', 'BJT-4', 'single', '「お電話番号をお教えいただけますでしょうか」の分析として正しいのは？
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (81100037, '「お電話番号」は謙譲語、「お教えいただく」は尊敬語', '「お電話番号」là Kenjougo, 「お教えいただく」là Sonkeigo', FALSE, 1);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (81100037, '「お電話番号」は丁寧語（相手の番号を丁寧に指す）、「お教えいただけます」は謙譲語（自分が教えてもらう）、「でしょうか」は丁寧語', '「お電話番号」= Teineigo (số điện thoại của ngài — lịch sự), 「お教えいただけます」= Kenjougo (mình được ngài cho biết), 「でしょうか」= Teineigo', TRUE, 2);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (81100037, 'この文は二重敬語なので間違い', 'Câu này là 二重敬語 nên sai', FALSE, 3);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (81100037, '「お電話番号」と「お教え」でおが重複しているので不自然', '「お電話番号」và「お教え」đều có お nên trùng lặp — không tự nhiên', FALSE, 4);
INSERT INTO questions (id, user_id, is_system, is_khoa_cu, question_type, content_type, level, selection_type, question, passage, passage_translation, general_explanation, skill_category, base_difficulty, tenant_id, is_active, is_deleted, created_at, created_by) VALUES (81100038, NULL, TRUE, FALSE, 'chon_dap_an', 'keigo_baitap_keigo_phan_loai', 'BJT-4', 'single', '次の4つの文を丁寧さの低い順に正しく並べてください。
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (81100038, '①→②→③→④', '① (thô nhất) → ② → ③ → ④ (lịch sự nhất)', TRUE, 1);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (81100038, '④→③→②→①', '④ (lịch sự nhất) → ③ → ② → ①', FALSE, 2);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (81100038, '②→①→③→④', '② → ① → ③ → ④', FALSE, 3);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (81100038, '①→③→②→④', '① → ③ → ② → ④', FALSE, 4);
INSERT INTO questions (id, user_id, is_system, is_khoa_cu, question_type, content_type, level, selection_type, question, passage, passage_translation, general_explanation, skill_category, base_difficulty, tenant_id, is_active, is_deleted, created_at, created_by) VALUES (81100039, NULL, TRUE, FALSE, 'chon_dap_an', 'keigo_baitap_keigo_phan_loai', 'BJT-4', 'single', '次の受付の会話で最も自然なものはどれですか？
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (81100039, '受付:「何のご用ですか」客:「田中部長に会いたい」受付:「少し待ってください」', 'Lễ tân: Có việc gì? / Khách: Muốn gặp Trưởng phòng Tanaka / Lễ tân: Chờ chút (thô)', FALSE, 1);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (81100039, '受付:「本日はどのようなご用件でいらっしゃいますか」客:「田中部長にご面会したいのですが」受付:「ただいまご連絡いたします。少々お待ちくださいませ」', 'Lễ tân: Hôm nay quý vị đến có việc gì ạ? / Khách: Tôi muốn gặp Trưởng phòng Tanaka ạ / Lễ tân: Tôi sẽ liên hệ ngay. Xin đợi chút ạ.', FALSE, 2);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (81100039, '受付:「何の用ですか」客:「田中部長に会いたいです」受付:「確認します」', 'Lễ tân: Có việc gì? / Khách: Tôi muốn gặp Trưởng phòng Tanaka / Lễ tân: Tôi sẽ xác nhận (bình thường)', FALSE, 3);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (81100039, 'B が全体的に最も自然でビジネス的', 'B tự nhiên và kinh doanh nhất tổng thể', TRUE, 4);
INSERT INTO questions (id, user_id, is_system, is_khoa_cu, question_type, content_type, level, selection_type, question, passage, passage_translation, general_explanation, skill_category, base_difficulty, tenant_id, is_active, is_deleted, created_at, created_by) VALUES (81100040, NULL, TRUE, FALSE, 'chon_dap_an', 'keigo_baitap_keigo_phan_loai', 'BJT-4', 'single', '「お客様がご利用になったサービスについて、弊社の担当者よりご説明申し上げます」の敬語を正しく分析したものはどれですか？
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (81100040, '全文が尊敬語', 'Toàn câu là Sonkeigo', FALSE, 1);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (81100040, '「ご利用になった」は尊敬語（お客様の行動）、「ご説明申し上げます」は謙譲語（担当者の行動）、全体の文体は丁寧語', '「ご利用になった」= Sonkeigo (hành động của khách) | 「ご説明申し上げます」= Kenjougo (hành động của nhân viên) | Văn phong toàn câu = Teineigo', TRUE, 2);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (81100040, '「ご利用になった」は謙譲語、「申し上げます」は尊敬語', '「ご利用になった」= Kenjougo, 「申し上げます」= Sonkeigo', FALSE, 3);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (81100040, '「弊社の担当者」の部分が間違っている', 'Phần「弊社の担当者」sai', FALSE, 4);
