INSERT INTO questions (id, user_id, is_system, is_khoa_cu, question_type, content_type, level, selection_type, question, passage, passage_translation, general_explanation, skill_category, base_difficulty, tenant_id, is_active, is_deleted, created_at, created_by) VALUES (82300018, NULL, TRUE, FALSE, 'chon_dap_an', 'keigo_baitap_keigo_phan_loai', 'BJT-2', 'single', '「お客様が資料を送ってくれた」を丁寧な尊敬語に直すと？
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (82300018, 'お客様が資料を送っていただいた', 'Được khách hàng gửi tài liệu cho. (いただく = Kenjougo — đổi góc nhìn)', FALSE, 1);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (82300018, 'お客様が資料をお送りくださった', 'Khách hàng đã gửi tài liệu cho tôi. (お送りくださる = Sonkeigo)', FALSE, 2);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (82300018, 'お客様が資料を送られた', 'Khách hàng đã gửi tài liệu. (〜れる = Sonkeigo nhẹ)', FALSE, 3);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (82300018, 'B と A は両方正しい', 'Cả B và A đều đúng nhưng góc nhìn khác nhau', TRUE, 4);
INSERT INTO questions (id, user_id, is_system, is_khoa_cu, question_type, content_type, level, selection_type, question, passage, passage_translation, general_explanation, skill_category, base_difficulty, tenant_id, is_active, is_deleted, created_at, created_by) VALUES (82300019, NULL, TRUE, FALSE, 'chon_dap_an', 'keigo_baitap_keigo_phan_loai', 'BJT-2', 'single', 'お客様が来た時の最初の挨拶として最も自然な表現はどれですか？
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (82300019, 'いらっしゃいませ。', 'Xin kính chào quý khách. (chào đón — chuẩn)', FALSE, 1);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (82300019, 'こんにちは、来ましたね。', 'Chào buổi chiều, bạn đến rồi nhỉ. (quá thân mật)', FALSE, 2);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (82300019, 'お越しいただきありがとうございます。', 'Cảm ơn quý vị đã ghé đến. (trang trọng, lịch sự cao)', FALSE, 3);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (82300019, 'A と C の両方が適切', 'Cả A và C đều phù hợp tùy ngữ cảnh', TRUE, 4);
INSERT INTO questions (id, user_id, is_system, is_khoa_cu, question_type, content_type, level, selection_type, question, passage, passage_translation, general_explanation, skill_category, base_difficulty, tenant_id, is_active, is_deleted, created_at, created_by) VALUES (82300020, NULL, TRUE, FALSE, 'chon_dap_an', 'keigo_baitap_keigo_phan_loai', 'BJT-2', 'single', '次の3つの表現を丁寧さの低い順に並べてください。
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (82300020, '③→②→①', '③ 読む (thông thường) → ② 読まれる (Sonkeigo nhẹ) → ① お読みになる (Sonkeigo mạnh)', TRUE, 1);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (82300020, '②→③→①', '② → ③ → ①', FALSE, 2);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (82300020, '①→②→③', '① (mạnh nhất) → ② → ③ (yếu nhất)', FALSE, 3);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (82300020, '③→①→②', '③ → ① → ②', FALSE, 4);
INSERT INTO questions (id, user_id, is_system, is_khoa_cu, question_type, content_type, level, selection_type, question, passage, passage_translation, general_explanation, skill_category, base_difficulty, tenant_id, is_active, is_deleted, created_at, created_by) VALUES (82300021, NULL, TRUE, FALSE, 'chon_dap_an', 'keigo_baitap_keigo_phan_loai', 'BJT-3', 'single', '電話で「山田様はいますか？」と聞かれた。山田さんは取引先の人です。正しい応答はどれですか？
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (82300021, 'はい、山田はおります。少々お待ちください。', 'Vâng, Yamada đang có mặt. Xin vui lòng chờ. (Kenjougo — dùng khi Yamada là Uchi)', FALSE, 1);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (82300021, 'はい、山田様はいらっしゃいます。少々お待ちください。', 'Vâng, ông Yamada đang có mặt ạ. Xin vui lòng chờ. (Sonkeigo — đúng vì Yamada là Soto)', TRUE, 2);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (82300021, 'はい、山田さんは来ています。待ってください。', 'Vâng, anh Yamada đang có mặt. Chờ nhé. (thông thường — không đủ lịch sự)', FALSE, 3);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (82300021, 'はい、山田様は参っております。少々お待ちください。', 'Vâng, ông Yamada đang có mặt ạ. (参る = Kenjougo — sai khi Yamada là Soto)', FALSE, 4);
INSERT INTO questions (id, user_id, is_system, is_khoa_cu, question_type, content_type, level, selection_type, question, passage, passage_translation, general_explanation, skill_category, base_difficulty, tenant_id, is_active, is_deleted, created_at, created_by) VALUES (82300022, NULL, TRUE, FALSE, 'chon_dap_an', 'keigo_baitap_keigo_phan_loai', 'BJT-3', 'single', 'メールで「先日送ったメールを見てもらいましたか」を最もビジネス的な表現にすると？
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (82300022, '先日お送りしたメールはご覧いただけましたでしょうか。', 'Email tôi kính gửi hôm trước, không biết quý vị đã xem qua chưa ạ?', FALSE, 1);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (82300022, '先日送ったメールをご覧になりましたでしょうか。', 'Email hôm trước, quý vị đã xem chưa ạ? (Sonkeigo thuần)', FALSE, 2);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (82300022, '先日ご送付いたしましたメールはお読みになりましたでしょうか。', 'Email tôi kính gửi hôm trước, quý vị đã đọc chưa ạ? (chuẩn, trang trọng)', FALSE, 3);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (82300022, 'A と C の両方が最もビジネス的', 'Cả A và C đều là tiếng Nhật kinh doanh chuẩn nhất', TRUE, 4);
INSERT INTO questions (id, user_id, is_system, is_khoa_cu, question_type, content_type, level, selection_type, question, passage, passage_translation, general_explanation, skill_category, base_difficulty, tenant_id, is_active, is_deleted, created_at, created_by) VALUES (82300023, NULL, TRUE, FALSE, 'chon_dap_an', 'keigo_baitap_keigo_phan_loai', 'BJT-3', 'single', 'お客様を会議室へ案内する時の正しい表現の順番はどれですか？
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (82300023, '①「こちらへどうぞ」②「会議室でございます」③「どうぞおかけください」', '① Mời đi theo lối này ② Đây là phòng họp ③ Mời ngài ngồi', FALSE, 1);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (82300023, '①「こっちに来て」②「部屋です」③「座ってください」', '① Đây này ② Đây là phòng ③ Ngồi đi (thô — không phù hợp)', FALSE, 2);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (82300023, '①「どうぞこちらへいらっしゃいませ」②「こちらが会議室でございます」③「どうぞおかけになってください」', '① Mời quý vị đi theo lối này ② Đây là phòng họp ③ Mời quý vị ngồi', FALSE, 3);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (82300023, 'A と C の両方が適切', 'Cả A và C đều phù hợp tùy mức độ trang trọng', TRUE, 4);
INSERT INTO questions (id, user_id, is_system, is_khoa_cu, question_type, content_type, level, selection_type, question, passage, passage_translation, general_explanation, skill_category, base_difficulty, tenant_id, is_active, is_deleted, created_at, created_by) VALUES (82300024, NULL, TRUE, FALSE, 'chon_dap_an', 'keigo_baitap_keigo_phan_loai', 'BJT-3', 'single', '「この書類にサインしてください」をお客様への丁寧な依頼に変えると？
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (82300024, 'この書類にサインなさってください。', 'Mời ngài ký vào tài liệu này ạ. (なさる = Sonkeigo của する)', FALSE, 1);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (82300024, 'こちらの書類にご署名いただけますでしょうか。', 'Liệu quý vị có thể ký tên vào tài liệu này không ạ? (ご署名 + いただく)', FALSE, 2);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (82300024, 'こちらの書類にご署名くださいますようお願い申し上げます。', 'Kính nhờ quý vị vui lòng ký tên vào tài liệu này ạ. (rất trang trọng — văn viết)', FALSE, 3);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (82300024, 'B と C は状況によって両方使える', 'B và C đều dùng được tùy tình huống', TRUE, 4);
INSERT INTO questions (id, user_id, is_system, is_khoa_cu, question_type, content_type, level, selection_type, question, passage, passage_translation, general_explanation, skill_category, base_difficulty, tenant_id, is_active, is_deleted, created_at, created_by) VALUES (82300025, NULL, TRUE, FALSE, 'chon_dap_an', 'keigo_baitap_keigo_phan_loai', 'BJT-3', 'single', '「お客様はすでに弊社のサービスを使ったことがありますか？」の敬語として正しいものは？
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (82300025, '弊社のサービスをすでにご利用になったことがおありでしょうか？', 'Không biết quý vị đã từng sử dụng dịch vụ của chúng tôi chưa ạ?', FALSE, 1);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (82300025, '弊社のサービスをすでにご利用されたことがありますか？', 'Quý vị đã từng sử dụng dịch vụ của chúng tôi chưa? (ご〜される — dùng kép sai)', FALSE, 2);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (82300025, '弊社のサービスをご使用いただきましたか？', 'Quý vị đã sử dụng dịch vụ của chúng tôi chưa? (いただく — Kenjougo góc nhìn khác)', FALSE, 3);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (82300025, 'A は正しい。C も正しいが視点が異なる', 'A đúng. C cũng đúng nhưng góc nhìn khác', TRUE, 4);
INSERT INTO questions (id, user_id, is_system, is_khoa_cu, question_type, content_type, level, selection_type, question, passage, passage_translation, general_explanation, skill_category, base_difficulty, tenant_id, is_active, is_deleted, created_at, created_by) VALUES (82300026, NULL, TRUE, FALSE, 'chon_dap_an', 'keigo_baitap_keigo_phan_loai', 'BJT-3', 'single', '取引先の田中部長から伝言を受けて、社内の上司に伝える場合。「田中部長が明日来ると言っていた」を正しい敬語にすると？
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (82300026, '田中部長が明日いらっしゃるとおっしゃっていました。', 'Trưởng phòng Tanaka nói rằng ngày mai ngài ấy sẽ đến. (Sonkeigo đầy đủ — vì Tanaka là Soto)', TRUE, 1);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (82300026, '田中部長が明日参るとおっしゃっていました。', 'Trưởng phòng Tanaka nói rằng ngày mai tôi sẽ đến. (参る = Kenjougo — sai ngữ cảnh)', FALSE, 2);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (82300026, '田中部長が明日来ると申していました。', 'Trưởng phòng Tanaka đã nói rằng ngày mai đến. (申す = Kenjougo — dùng sai cho người Soto)', FALSE, 3);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (82300026, '田中部長が明日いらっしゃると申していました。', 'Trưởng phòng Tanaka đã nói rằng ngày mai ngài ấy sẽ đến. (hỗn hợp — sai)', FALSE, 4);
INSERT INTO questions (id, user_id, is_system, is_khoa_cu, question_type, content_type, level, selection_type, question, passage, passage_translation, general_explanation, skill_category, base_difficulty, tenant_id, is_active, is_deleted, created_at, created_by) VALUES (82300027, NULL, TRUE, FALSE, 'chon_dap_an', 'keigo_baitap_keigo_phan_loai', 'BJT-3', 'single', 'お客様の住所を確認する時、最も丁寧な表現はどれですか？
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (82300027, '住所はどこですか？', 'Địa chỉ ở đâu? (thô)', FALSE, 1);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (82300027, 'ご住所をお聞かせいただけますでしょうか？', 'Không biết quý vị có thể cho biết địa chỉ không ạ? (ご住所 + お聞かせいただく)', TRUE, 2);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (82300027, 'ご住所はいかがでしょうか？', 'Địa chỉ của ngài là thế nào ạ? (いかが = cách hỏi lịch sự nhưng không tự nhiên ở đây)', FALSE, 3);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (82300027, 'ご住所をおっしゃっていただけますか？', 'Quý vị có thể nói địa chỉ không ạ? (おっしゃる + いただく — kết hợp sai)', FALSE, 4);
INSERT INTO questions (id, user_id, is_system, is_khoa_cu, question_type, content_type, level, selection_type, question, passage, passage_translation, general_explanation, skill_category, base_difficulty, tenant_id, is_active, is_deleted, created_at, created_by) VALUES (82300028, NULL, TRUE, FALSE, 'chon_dap_an', 'keigo_baitap_keigo_phan_loai', 'BJT-3', 'single', 'お礼メールの一節: 「先日は（　）ありがとうございました」— 「来てくれた」の尊敬語を入れてください。
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (82300028, '来ていただき', '来ていただき (Kenjougo: được ngài đến)', FALSE, 1);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (82300028, 'いらっしゃっていただき', 'いらっしゃっていただき (Sonkeigo + いただく — kết hợp cao cấp)', FALSE, 2);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (82300028, 'お越しくださり', 'お越しくださり (お越し + くださる — Sonkeigo chuẩn cao)', FALSE, 3);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (82300028, 'C が最も自然でビジネス的', 'C tự nhiên và kinh doanh nhất', TRUE, 4);
INSERT INTO questions (id, user_id, is_system, is_khoa_cu, question_type, content_type, level, selection_type, question, passage, passage_translation, general_explanation, skill_category, base_difficulty, tenant_id, is_active, is_deleted, created_at, created_by) VALUES (82300029, NULL, TRUE, FALSE, 'chon_dap_an', 'keigo_baitap_keigo_phan_loai', 'BJT-3', 'single', '「先生のおっしゃる通りです」— この文について正しい説明はどれですか？
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (82300029, '「おっしゃる通り」は「言った通り」の謙譲語表現', '「おっしゃる通り」là Kenjougo của 言った通り', FALSE, 1);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (82300029, '「おっしゃる通り」は「言われた通り」の尊敬語表現で、同意を示す決まり文句', '「おっしゃる通り」là Sonkeigo của 言われた通り — thành ngữ thể hiện sự đồng ý', TRUE, 2);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (82300029, '「おっしゃる通り」は丁寧語で、誰にでも使える', '「おっしゃる通り」là Teineigo, dùng được với bất kỳ ai', FALSE, 3);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (82300029, 'この文は間違っている — 「おっしゃられる通り」が正しい', 'Câu này sai — phải là「おっしゃられる通り」', FALSE, 4);
INSERT INTO questions (id, user_id, is_system, is_khoa_cu, question_type, content_type, level, selection_type, question, passage, passage_translation, general_explanation, skill_category, base_difficulty, tenant_id, is_active, is_deleted, created_at, created_by) VALUES (82300030, NULL, TRUE, FALSE, 'chon_dap_an', 'keigo_baitap_keigo_phan_loai', 'BJT-3', 'single', '次の会話で、下線部の敬語として最も適切なものはどれですか？
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (82300030, '完成いたす', '完成いたす (Kenjougo — hành động của mình)', FALSE, 1);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (82300030, '完成なさる', '完成なさる (Sonkeigo của する — nhưng chủ ngữ ở đây là gì?)', FALSE, 2);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (82300030, '完成する', '完成する (thông thường)', FALSE, 3);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (82300030, '完成いたす — chủ ngữ ngầm là ''chúng tôi'' nên Kenjougo là đúng', '完成いたす — vì chủ ngữ là ''chúng tôi'' (Uchi), Kenjougo mới đúng', TRUE, 4);
INSERT INTO questions (id, user_id, is_system, is_khoa_cu, question_type, content_type, level, selection_type, question, passage, passage_translation, general_explanation, skill_category, base_difficulty, tenant_id, is_active, is_deleted, created_at, created_by) VALUES (82300031, NULL, TRUE, FALSE, 'chon_dap_an', 'keigo_baitap_keigo_phan_loai', 'BJT-4', 'single', '次の文の中で、二重敬語（間違った敬語の重複使用）があるものはどれですか？
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (82300031, 'お客様がおっしゃいました。', 'Khách hàng đã nói ạ.', FALSE, 1);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (82300031, '社長がいらっしゃられました。', 'Giám đốc đã đến ạ. (いらっしゃる + られる = kép)', TRUE, 2);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (82300031, 'ご利用になりましたか？', 'Ngài đã sử dụng chưa ạ?', FALSE, 3);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (82300031, 'お読みになりましたか？', 'Ngài đã đọc chưa ạ?', FALSE, 4);
INSERT INTO questions (id, user_id, is_system, is_khoa_cu, question_type, content_type, level, selection_type, question, passage, passage_translation, general_explanation, skill_category, base_difficulty, tenant_id, is_active, is_deleted, created_at, created_by) VALUES (82300032, NULL, TRUE, FALSE, 'chon_dap_an', 'keigo_baitap_keigo_phan_loai', 'BJT-4', 'single', '次のうち、二重敬語ではなく正しい敬語表現はどれですか？
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (82300032, 'おっしゃられました', 'おっしゃられました (おっしゃる + られる = kép ❌)', FALSE, 1);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (82300032, 'なさられました', 'なさられました (なさる + られる = kép ❌)', FALSE, 2);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (82300032, 'ご覧になりました', 'ご覧になりました (ご覧 + になる = cấu trúc đúng ✅)', TRUE, 3);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (82300032, '召し上がられました', '召し上がられました (召し上がる + られる = kép ❌)', FALSE, 4);
INSERT INTO questions (id, user_id, is_system, is_khoa_cu, question_type, content_type, level, selection_type, question, passage, passage_translation, general_explanation, skill_category, base_difficulty, tenant_id, is_active, is_deleted, created_at, created_by) VALUES (82300033, NULL, TRUE, FALSE, 'chon_dap_an', 'keigo_baitap_keigo_phan_loai', 'BJT-4', 'single', 'あなたはA社員。B社のC部長（取引先）から「D社長（B社の社長）は来ますか？」と聞かれました。D社長がまだ来ていない場合、正しい答えは？
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (82300033, 'D社長はまだおりません。', 'Chủ tịch D chưa đến. (おる = Kenjougo — SAI vì Chủ tịch D là Soto)', FALSE, 1);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (82300033, 'D社長はまだいらっしゃいません。', 'Chủ tịch D chưa đến ạ. (Sonkeigo — ĐÚNG vì D là người ngoài công ty mình)', TRUE, 2);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (82300033, 'D社長はまだ参っておりません。', 'Chủ tịch D chưa đến ạ. (参る = Kenjougo — SAI)', FALSE, 3);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (82300033, 'D社長はまだ来ておりません。', 'Chủ tịch D chưa đến ạ. (おる = Kenjougo — SAI)', FALSE, 4);
INSERT INTO questions (id, user_id, is_system, is_khoa_cu, question_type, content_type, level, selection_type, question, passage, passage_translation, general_explanation, skill_category, base_difficulty, tenant_id, is_active, is_deleted, created_at, created_by) VALUES (82300034, NULL, TRUE, FALSE, 'chon_dap_an', 'keigo_baitap_keigo_phan_loai', 'BJT-4', 'single', '次の文のうち、敬語が完全に正しいものはどれですか？（全てお客様に対する発言）
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (82300034, 'お客様がお越しになりました際に、弊社の田中がご説明いたします。', 'Khi quý vị đến, Tanaka bên tôi sẽ giải thích. (Sonkeigo cho khách + Kenjougo cho mình)', TRUE, 1);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (82300034, 'お客様がいらっしゃいました際に、田中部長がご説明いたします。', 'Khi quý vị đến, Trưởng phòng Tanaka sẽ giải thích. (Sonkeigo cho khách ✅, nhưng 田中部長 phải bỏ 部長)', FALSE, 2);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (82300034, 'お客様がいらっしゃった際に、弊社の田中がご説明なさいます。', 'Khi quý vị đến, Tanaka bên tôi sẽ giải thích. (ご説明なさる = Sonkeigo cho Tanaka — SAI vì Tanaka là Uchi)', FALSE, 3);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (82300034, 'お越しいただいた際に、弊社の田中がご説明させていただきます。', 'Khi quý vị ghé đến, Tanaka bên tôi xin được giải thích. (tự nhiên, khiêm nhường)', FALSE, 4);
INSERT INTO questions (id, user_id, is_system, is_khoa_cu, question_type, content_type, level, selection_type, question, passage, passage_translation, general_explanation, skill_category, base_difficulty, tenant_id, is_active, is_deleted, created_at, created_by) VALUES (82300035, NULL, TRUE, FALSE, 'chon_dap_an', 'keigo_baitap_keigo_phan_loai', 'BJT-4', 'single', '「もし時間があれば、来てください」をお客様への丁寧な依頼にすると？
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (82300035, 'もしよろしければ、お越しくださいませ。', 'Nếu quý vị thuận tiện, mời ngài ghé đến ạ.', FALSE, 1);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (82300035, 'もしよろしければ、いらっしゃってください。', 'Nếu thuận tiện, mời ngài đến ạ. (hơi trực tiếp)', FALSE, 2);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (82300035, 'もしよろしければ、ぜひお越しいただけますと幸いでございます。', 'Nếu quý vị thuận tiện, rất hân hạnh nếu ngài có thể ghé đến ạ. (rất trang trọng)', FALSE, 3);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (82300035, 'A と C の両方が状況に応じて使える', 'Cả A và C đều dùng được tùy tình huống', TRUE, 4);
INSERT INTO questions (id, user_id, is_system, is_khoa_cu, question_type, content_type, level, selection_type, question, passage, passage_translation, general_explanation, skill_category, base_difficulty, tenant_id, is_active, is_deleted, created_at, created_by) VALUES (82300036, NULL, TRUE, FALSE, 'chon_dap_an', 'keigo_baitap_keigo_phan_loai', 'BJT-4', 'single', '上司が会議中に部下に対して使う表現として、不適切なものはどれですか？
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (82300036, 'この資料を見てください。', 'Hãy xem tài liệu này nhé. (thông thường — OK với cấp dưới)', FALSE, 1);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (82300036, 'この件についてどう思いますか？', 'Bạn nghĩ thế nào về vấn đề này? (thông thường — OK)', FALSE, 2);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (82300036, 'ご意見をいただけますか？', 'Liệu tôi có thể nhận ý kiến của bạn không? (Kenjougo — quá cung kính với cấp dưới)', TRUE, 3);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (82300036, '少し待ってください。', 'Đợi một chút nhé. (thông thường — OK)', FALSE, 4);
INSERT INTO questions (id, user_id, is_system, is_khoa_cu, question_type, content_type, level, selection_type, question, passage, passage_translation, general_explanation, skill_category, base_difficulty, tenant_id, is_active, is_deleted, created_at, created_by) VALUES (82300037, NULL, TRUE, FALSE, 'chon_dap_an', 'keigo_baitap_keigo_phan_loai', 'BJT-4', 'single', '招待状の一文:「ご多忙のところ誠に恐縮ですが、ぜひご（　）いただければ幸いでございます」— 「出席する」の尊敬語形を入れてください。
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (82300037, '出席し', '出席し (thông thường — không đủ trang trọng)', FALSE, 1);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (82300037, '出席なさり', 'ご出席なさり (Sonkeigo của する — nhưng kết hợp với いただく là không tự nhiên)', FALSE, 2);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (82300037, '出席', 'ご出席いただければ (ご + 出席 + いただく — chuẩn nhất)', TRUE, 3);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (82300037, '参加いただき', 'ご参加いただき (cũng đúng với ý tham dự)', FALSE, 4);
INSERT INTO questions (id, user_id, is_system, is_khoa_cu, question_type, content_type, level, selection_type, question, passage, passage_translation, general_explanation, skill_category, base_difficulty, tenant_id, is_active, is_deleted, created_at, created_by) VALUES (82300038, NULL, TRUE, FALSE, 'chon_dap_an', 'keigo_baitap_keigo_phan_loai', 'BJT-4', 'single', 'BJTでよく出る問題: 「（　）はご存知ですか？」— 主語として最も不自然なものは？
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (82300038, 'この件（このけん）', 'この件 (vấn đề này) — bình thường', FALSE, 1);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (82300038, '弊社の新製品', '弊社の新製品 (sản phẩm mới của chúng tôi) — bình thường', FALSE, 2);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (82300038, '私のこと', '私のこと (về tôi) — có vẻ hơi kỳ nhưng có thể dùng', FALSE, 3);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (82300038, 'わたくしの意見', 'わたくしの意見 (ý kiến của tôi) — hỏi người khác về ý kiến của mình bằng ご存知 là không phù hợp', TRUE, 4);
INSERT INTO questions (id, user_id, is_system, is_khoa_cu, question_type, content_type, level, selection_type, question, passage, passage_translation, general_explanation, skill_category, base_difficulty, tenant_id, is_active, is_deleted, created_at, created_by) VALUES (82300039, NULL, TRUE, FALSE, 'chon_dap_an', 'keigo_baitap_keigo_phan_loai', 'BJT-4', 'single', '次の会話を完成させてください。
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (82300039, '「わかりました」/ お伝え', '「わかりました」(hiểu rồi) / お伝え (truyền đạt — Kenjougo)', FALSE, 1);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (82300039, '「了解」/ お知らせ', '「了解」(OK — không phù hợp với sếp) / お知らせ', FALSE, 2);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (82300039, '「承知しました」/ お伝え', '「承知しました」(vâng ạ — Kenjougo) / お伝え — chuẩn nhất', TRUE, 3);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (82300039, '「かしこまりました」/ 申し上げ', '「かしこまりました」(tuân lệnh — trang trọng nhất) / 申し上げ', FALSE, 4);
INSERT INTO questions (id, user_id, is_system, is_khoa_cu, question_type, content_type, level, selection_type, question, passage, passage_translation, general_explanation, skill_category, base_difficulty, tenant_id, is_active, is_deleted, created_at, created_by) VALUES (82300040, NULL, TRUE, FALSE, 'chon_dap_an', 'keigo_baitap_keigo_phan_loai', 'BJT-4', 'single', '次のメール文の下線部で、最も不自然または間違った表現はどれですか？
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (82300040, '① いつもお世話になっております', '① いつもお世話になっております', FALSE, 1);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (82300040, '② ご来社いただきまして', '② ご来社いただきまして', FALSE, 2);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (82300040, '④ いらっしゃられたこと', '④ いらっしゃられたこと — 二重敬語!', TRUE, 3);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (82300040, '⑤ 重ねて御礼申し上げます', '⑤ 重ねて御礼申し上げます', FALSE, 4);
