INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (83300005, '拝見する＝見る の尊敬語、伺う＝行く の謙譲語', '拝見する = Sonkeigo của 見る | 伺う = Kenjougo của 行く', FALSE, 2);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (83300005, '拝見する＝見る の謙譲語、伺う＝訪ねる/聞く の謙譲語', '拝見する = Kenjougo của 見る | 伺う = Kenjougo của 訪ねる/聞く', TRUE, 3);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (83300005, '拝見する＝見る の謙譲語、伺う＝行く/来る の謙譲語', '拝見する = Kenjougo của 見る | 伺う = Kenjougo của 行く/来る', FALSE, 4);
