INSERT INTO questions (id, user_id, is_system, is_khoa_cu, question_type, content_type, level, selection_type, question, passage, passage_translation, general_explanation, skill_category, base_difficulty, tenant_id, is_active, is_deleted, created_at, created_by) VALUES (83300010, NULL, TRUE, FALSE, 'chon_dap_an', 'keigo_baitap_keigo_phan_loai', 'BJT-1', 'single', '「私（わたし）」のより謙虚な言い方として正しいものはどれですか？
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (83300010, 'あたし', 'あたし (thân mật, nữ tính — không trang trọng hơn)', FALSE, 1);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (83300010, 'わたくし', 'わたくし (trang trọng và khiêm nhường hơn わたし)', TRUE, 2);
