INSERT INTO questions (id, user_id, is_system, is_khoa_cu, question_type, content_type, level, selection_type, question, passage, passage_translation, general_explanation, skill_category, base_difficulty, tenant_id, is_active, is_deleted, created_at, created_by) VALUES (83300011, NULL, TRUE, FALSE, 'chon_dap_an', 'keigo_baitap_keigo_phan_loai', 'BJT-2', 'single', '「荷物を持ちましょうか？」をお客様への丁寧な謙譲語に直すと？
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (83300011, '荷物をお持ちになりましょうか？', 'Ngài có muốn mang hành lý không? (お〜になる = Sonkeigo — sai chủ ngữ)', FALSE, 1);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (83300011, '荷物をお持ちしましょうか？', 'Tôi mang hành lý giúp quý vị nhé ạ? (お〜する = Kenjougo — đúng)', FALSE, 2);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (83300011, '荷物を持ってあげましょうか？', 'Tôi mang hành lý cho ngài nhé? (あげる — nghe kiêu ngạo, không phù hợp)', FALSE, 3);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (83300011, '荷物をお持ちいたしましょうか？', 'Tôi xin mang hành lý giúp quý vị nhé ạ? (お〜いたす = Kenjougo trang trọng hơn)', TRUE, 4);
INSERT INTO questions (id, user_id, is_system, is_khoa_cu, question_type, content_type, level, selection_type, question, passage, passage_translation, general_explanation, skill_category, base_difficulty, tenant_id, is_active, is_deleted, created_at, created_by) VALUES (83300012, NULL, TRUE, FALSE, 'chon_dap_an', 'keigo_baitap_keigo_phan_loai', 'BJT-2', 'single', '「説明します」を謙譲語にすると？（gốc Hán — ご〜する を使う）
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (83300012, 'ご説明になります', 'ご説明になります (ご〜になる = Sonkeigo — sai)', FALSE, 1);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (83300012, 'ご説明します', 'ご説明します (đúng — mức cơ bản)', FALSE, 2);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (83300012, 'ご説明いたします', 'ご説明いたします (đúng — mức trang trọng hơn)', FALSE, 3);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (83300012, 'B と C の両方が正しい謙譲語', 'Cả B và C đều là Kenjougo đúng', TRUE, 4);
INSERT INTO questions (id, user_id, is_system, is_khoa_cu, question_type, content_type, level, selection_type, question, passage, passage_translation, general_explanation, skill_category, base_difficulty, tenant_id, is_active, is_deleted, created_at, created_by) VALUES (83300013, NULL, TRUE, FALSE, 'chon_dap_an', 'keigo_baitap_keigo_phan_loai', 'BJT-2', 'single', '「〜させていただく」の正しい使い方として適切なのはどれですか？
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (83300013, '確認させていただきます。', 'Tôi xin phép được xác nhận ạ. (mình làm — đúng)', TRUE, 1);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (83300013, 'お客様に確認させていただきます。', 'Tôi sẽ để khách hàng xác nhận. (chủ ngữ nhầm — sai ngữ nghĩa)', FALSE, 2);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (83300013, '確認させていただいてください。', 'Hãy để tôi được xác nhận. (命令形 kết hợp させていただく — sai)', FALSE, 3);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (83300013, 'ご確認させていただきます。', 'Tôi xin phép được xác nhận ạ. (ご + させていただく — 二重敬語?)', FALSE, 4);
INSERT INTO questions (id, user_id, is_system, is_khoa_cu, question_type, content_type, level, selection_type, question, passage, passage_translation, general_explanation, skill_category, base_difficulty, tenant_id, is_active, is_deleted, created_at, created_by) VALUES (83300014, NULL, TRUE, FALSE, 'chon_dap_an', 'keigo_baitap_keigo_phan_loai', 'BJT-2', 'single', '次の2つの文の違いを正しく説明しているのはどれですか？
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (83300014, '①は謙譲語、②は尊敬語。意味は同じだが主語の視点が異なる', '① là Kenjougo, ② là Sonkeigo. Nghĩa gần nhau nhưng góc nhìn chủ ngữ khác nhau', TRUE, 1);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (83300014, '①は間違い、②だけが正しい', '① sai, chỉ ② đúng', FALSE, 2);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (83300014, '②は間違い、①だけが正しい', '② sai, chỉ ① đúng', FALSE, 3);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (83300014, '両方とも同じ意味で、違いはない', 'Cả hai giống nhau hoàn toàn, không có gì khác', FALSE, 4);
INSERT INTO questions (id, user_id, is_system, is_khoa_cu, question_type, content_type, level, selection_type, question, passage, passage_translation, general_explanation, skill_category, base_difficulty, tenant_id, is_active, is_deleted, created_at, created_by) VALUES (83300015, NULL, TRUE, FALSE, 'chon_dap_an', 'keigo_baitap_keigo_phan_loai', 'BJT-2', 'single', '初めて会う取引先に自己紹介する時、最も適切な表現はどれですか？
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (83300015, '田中です。よろしく。', 'Tôi là Tanaka. Nhờ bạn nhé.', FALSE, 1);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (83300015, '田中と言います。どうぞよろしくお願いします。', 'Tôi tên là Tanaka. Rất mong được hợp tác.', FALSE, 2);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (83300015, '田中と申します。どうぞよろしくお願いいたします。', 'Tôi tên là Tanaka. Kính mong được hợp tác ạ. (申す + いたす)', TRUE, 3);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (83300015, '私の名前は田中でございます。よろしくお願い申し上げます。', 'Tên tôi là Tanaka. Kính nhờ quý vị. (trang trọng — hơi quá mức cho lần đầu)', FALSE, 4);
INSERT INTO questions (id, user_id, is_system, is_khoa_cu, question_type, content_type, level, selection_type, question, passage, passage_translation, general_explanation, skill_category, base_difficulty, tenant_id, is_active, is_deleted, created_at, created_by) VALUES (83300016, NULL, TRUE, FALSE, 'chon_dap_an', 'keigo_baitap_keigo_phan_loai', 'BJT-2', 'single', '部下が上司に「資料を見ました」と報告する時、正しい謙譲語は？
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (83300016, '資料をご覧になりました。', 'Ngài đã xem tài liệu. (Sonkeigo — chủ ngữ sai)', FALSE, 1);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (83300016, '資料を拝見いたしました。', 'Tôi đã kính xem tài liệu ạ. (拝見する + いたす — Kenjougo)', FALSE, 2);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (83300016, '資料を見させていただきました。', 'Tôi đã được phép xem tài liệu ạ. (させていただく — Kenjougo)', FALSE, 3);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (83300016, 'B と C の両方が正しい', 'Cả B và C đều đúng', TRUE, 4);
INSERT INTO questions (id, user_id, is_system, is_khoa_cu, question_type, content_type, level, selection_type, question, passage, passage_translation, general_explanation, skill_category, base_difficulty, tenant_id, is_active, is_deleted, created_at, created_by) VALUES (83300017, NULL, TRUE, FALSE, 'chon_dap_an', 'keigo_baitap_keigo_phan_loai', 'BJT-2', 'single', 'お客様に「後でもう一度電話します」を丁寧に伝えると？
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (83300017, '後でまた電話します。', 'Tôi sẽ gọi lại sau. (thông thường)', FALSE, 1);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (83300017, '後ほど折り返しお電話いたします。', 'Tôi sẽ gọi lại cho quý vị sau ạ. (Kenjougo chuẩn)', FALSE, 2);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (83300017, '後でお電話させていただきます。', 'Tôi xin phép gọi lại cho quý vị sau ạ. (させていただく)', FALSE, 3);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (83300017, 'B と C の両方が適切', 'Cả B và C đều phù hợp', TRUE, 4);
INSERT INTO questions (id, user_id, is_system, is_khoa_cu, question_type, content_type, level, selection_type, question, passage, passage_translation, general_explanation, skill_category, base_difficulty, tenant_id, is_active, is_deleted, created_at, created_by) VALUES (83300018, NULL, TRUE, FALSE, 'chon_dap_an', 'keigo_baitap_keigo_phan_loai', 'BJT-2', 'single', 'お客様から依頼を受けた時、正しい承諾表現の順（丁寧さ低→高）はどれですか？
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (83300018, '③→②→①', '③ わかりました (thường) → ② 承知しました (lịch sự) → ① かしこまりました (trang trọng nhất)', TRUE, 1);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (83300018, '①→②→③', '① → ② → ③', FALSE, 2);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (83300018, '②→③→①', '② → ③ → ①', FALSE, 3);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (83300018, '③→①→②', '③ → ① → ②', FALSE, 4);
INSERT INTO questions (id, user_id, is_system, is_khoa_cu, question_type, content_type, level, selection_type, question, passage, passage_translation, general_explanation, skill_category, base_difficulty, tenant_id, is_active, is_deleted, created_at, created_by) VALUES (83300019, NULL, TRUE, FALSE, 'chon_dap_an', 'keigo_baitap_keigo_phan_loai', 'BJT-2', 'single', '上司に「聞いていいですか？」と言う時、最も適切な謙譲語は？
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (83300019, '聞いていいですか？', 'Tôi có thể hỏi không? (thông thường)', FALSE, 1);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (83300019, 'お聞きしてもよろしいでしょうか？', 'Tôi có thể hỏi được không ạ? (お〜する)', FALSE, 2);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (83300019, '一つ伺ってもよろしいでしょうか？', 'Tôi có thể thưa hỏi một điều không ạ? (伺う = Kenjougo)', FALSE, 3);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (83300019, 'B と C の両方が正しい', 'Cả B và C đều đúng', TRUE, 4);
INSERT INTO questions (id, user_id, is_system, is_khoa_cu, question_type, content_type, level, selection_type, question, passage, passage_translation, general_explanation, skill_category, base_difficulty, tenant_id, is_active, is_deleted, created_at, created_by) VALUES (83300020, NULL, TRUE, FALSE, 'chon_dap_an', 'keigo_baitap_keigo_phan_loai', 'BJT-2', 'single', '「知りません」を上司やお客様に対して正しい謙譲語で言うと？
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (83300020, '知りません。', 'Tôi không biết. (thô, thiếu lịch sự)', FALSE, 1);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (83300020, 'わかりません。', 'Tôi không hiểu. (thông thường)', FALSE, 2);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (83300020, '存じません。', 'Tôi không biết ạ. (存じる phủ định — Kenjougo)', TRUE, 3);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (83300020, 'ご存知ではありません。', 'Ngài không biết. (Sonkeigo — sai chủ ngữ)', FALSE, 4);
INSERT INTO questions (id, user_id, is_system, is_khoa_cu, question_type, content_type, level, selection_type, question, passage, passage_translation, general_explanation, skill_category, base_difficulty, tenant_id, is_active, is_deleted, created_at, created_by) VALUES (83300021, NULL, TRUE, FALSE, 'chon_dap_an', 'keigo_baitap_keigo_phan_loai', 'BJT-3', 'single', 'お客様から「山田部長はいますか？」と聞かれた。山田部長は自分の会社の上司です。正しい答えは？
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (83300021, 'はい、山田部長はいらっしゃいます。', 'Vâng, Trưởng phòng Yamada đang có mặt. (Sonkeigo — SAI vì Yamada là Uchi)', FALSE, 1);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (83300021, 'はい、山田はただいまおります。', 'Vâng, Yamada hiện đang có mặt ạ. (Kenjougo + bỏ 部長 — ĐÚNG)', TRUE, 2);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (83300021, 'はい、山田部長はおります。', 'Vâng, Trưởng phòng Yamada đang có mặt. (Kenjougo ✅, nhưng giữ 部長 — một phần sai)', FALSE, 3);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (83300021, 'はい、山田は参っております。', 'Vâng, Yamada đang có mặt. (参る = đi/đến, không phải ''ở'' — sai dùng từ)', FALSE, 4);
INSERT INTO questions (id, user_id, is_system, is_khoa_cu, question_type, content_type, level, selection_type, question, passage, passage_translation, general_explanation, skill_category, base_difficulty, tenant_id, is_active, is_deleted, created_at, created_by) VALUES (83300022, NULL, TRUE, FALSE, 'chon_dap_an', 'keigo_baitap_keigo_phan_loai', 'BJT-3', 'single', '担当者が不在で、お客様から伝言を受ける時、最も丁寧な表現はどれですか？
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (83300022, 'メモしておきます。', 'Tôi sẽ ghi lại. (thông thường)', FALSE, 1);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (83300022, '伝えておきます。', 'Tôi sẽ truyền đạt lại. (thông thường)', FALSE, 2);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (83300022, 'ご伝言を承ります。', 'Tôi xin nhận lời nhắn của quý vị. (ご伝言 + 承る = Kenjougo)', TRUE, 3);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (83300022, 'おっしゃったことをお伝えいたします。', 'Tôi sẽ truyền đạt điều ngài đã nói ạ. (おっしゃる + お伝えいたす)', FALSE, 4);
INSERT INTO questions (id, user_id, is_system, is_khoa_cu, question_type, content_type, level, selection_type, question, passage, passage_translation, general_explanation, skill_category, base_difficulty, tenant_id, is_active, is_deleted, created_at, created_by) VALUES (83300023, NULL, TRUE, FALSE, 'chon_dap_an', 'keigo_baitap_keigo_phan_loai', 'BJT-3', 'single', 'メールの書き出しとして「先日はありがとうございました」を最もビジネス的な謙譲語に直すと？
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (83300023, '先日はご来社いただき、誠にありがとうございました。', 'Cảm ơn quý vị đã ghé đến công ty chúng tôi hôm trước ạ. (ご来社いただく)', FALSE, 1);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (83300023, '先日はお越しいただき、ありがとうございました。', 'Cảm ơn quý vị đã ghé đến hôm trước ạ. (お越しいただく)', FALSE, 2);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (83300023, '先日はご足労いただき、誠にありがとうございました。', 'Cảm ơn quý vị đã không quản đường sá hôm trước ạ. (ご足労 = khó nhọc đi đường — rất trang trọng)', FALSE, 3);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (83300023, '状況によって全て正しい', 'Tất cả đều đúng tùy tình huống cụ thể', TRUE, 4);
INSERT INTO questions (id, user_id, is_system, is_khoa_cu, question_type, content_type, level, selection_type, question, passage, passage_translation, general_explanation, skill_category, base_difficulty, tenant_id, is_active, is_deleted, created_at, created_by) VALUES (83300024, NULL, TRUE, FALSE, 'chon_dap_an', 'keigo_baitap_keigo_phan_loai', 'BJT-3', 'single', 'お客様の依頼を断る時、最も丁寧な謙譲語の表現はどれですか？
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (83300024, 'できません。', 'Tôi không thể làm được. (thô)', FALSE, 1);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (83300024, '申し訳ありませんが、できかねます。', 'Xin lỗi, tôi e rằng khó có thể làm được. (できかねる)', FALSE, 2);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (83300024, '誠に恐れ入りますが、いたしかねます。', 'Thực sự xin lỗi ạ, tôi e rằng khó có thể thực hiện được. (いたしかねる — Kenjougo)', TRUE, 3);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (83300024, 'あいにくですが、対応いたしかねる状況でございます。', 'Thật tiếc, hiện tại chúng tôi ở tình trạng khó có thể đáp ứng được ạ. (rất trang trọng)', FALSE, 4);
INSERT INTO questions (id, user_id, is_system, is_khoa_cu, question_type, content_type, level, selection_type, question, passage, passage_translation, general_explanation, skill_category, base_difficulty, tenant_id, is_active, is_deleted, created_at, created_by) VALUES (83300025, NULL, TRUE, FALSE, 'chon_dap_an', 'keigo_baitap_keigo_phan_loai', 'BJT-3', 'single', '会議の前に、上司に資料を確認してもらいたい時、最も適切な謙譲語は？
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (83300025, '資料を確認してください。', 'Hãy kiểm tra tài liệu giùm tôi. (mệnh lệnh — không phù hợp với cấp trên)', FALSE, 1);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (83300025, '資料をご確認いただけますでしょうか。', 'Không biết cấp trên có thể xem qua tài liệu không ạ? (Kenjougo + lịch sự)', FALSE, 2);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (83300025, 'よろしければ、資料にお目通しいただけますか。', 'Nếu tiện, sếp có thể lướt qua tài liệu không ạ? (お目通し = xem lướt qua)', FALSE, 3);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (83300025, 'B と C の両方が状況に応じて使える', 'Cả B và C đều dùng được tùy tình huống', TRUE, 4);
INSERT INTO questions (id, user_id, is_system, is_khoa_cu, question_type, content_type, level, selection_type, question, passage, passage_translation, general_explanation, skill_category, base_difficulty, tenant_id, is_active, is_deleted, created_at, created_by) VALUES (83300026, NULL, TRUE, FALSE, 'chon_dap_an', 'keigo_baitap_keigo_phan_loai', 'BJT-3', 'single', 'お客様に「部長の田中から伝言があります」を伝える正しい敬語表現は？
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (83300026, '田中部長からご伝言がございます。', 'Trưởng phòng Tanaka có lời nhắn ạ. (ご伝言 + ございます — sai vì dùng kính ngữ cho Uchi)', FALSE, 1);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (83300026, '田中よりお言付けを申し伝えます。', 'Tanaka nhờ tôi chuyển lời ạ. (Kenjougo — đúng)', FALSE, 2);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (83300026, '田中が申しておりましたことをお伝えいたします。', 'Tôi xin chuyển điều mà Tanaka đã nói ạ. (申す + お伝えいたす — Kenjougo chuẩn)', FALSE, 3);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (83300026, 'B と C の両方が正しい', 'Cả B và C đều đúng', TRUE, 4);
INSERT INTO questions (id, user_id, is_system, is_khoa_cu, question_type, content_type, level, selection_type, question, passage, passage_translation, general_explanation, skill_category, base_difficulty, tenant_id, is_active, is_deleted, created_at, created_by) VALUES (83300027, NULL, TRUE, FALSE, 'chon_dap_an', 'keigo_baitap_keigo_phan_loai', 'BJT-3', 'single', '取引先へのメールで「日程を教えてほしい」を丁寧に書くと？
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (83300027, '日程を教えてください。', 'Hãy cho tôi biết lịch trình. (mệnh lệnh — thô)', FALSE, 1);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (83300027, 'ご都合のよい日程をお知らせいただけますと幸いです。', 'Rất vui nếu quý vị có thể cho biết lịch trình thuận tiện ạ. (お知らせいただく + 幸い)', FALSE, 2);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (83300027, 'ご日程をご教示いただけますでしょうか。', 'Không biết quý vị có thể chỉ dạy về lịch trình không ạ? (ご教示いただく)', FALSE, 3);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (83300027, 'B と C の両方が正しい', 'Cả B và C đều đúng', TRUE, 4);
INSERT INTO questions (id, user_id, is_system, is_khoa_cu, question_type, content_type, level, selection_type, question, passage, passage_translation, general_explanation, skill_category, base_difficulty, tenant_id, is_active, is_deleted, created_at, created_by) VALUES (83300028, NULL, TRUE, FALSE, 'chon_dap_an', 'keigo_baitap_keigo_phan_loai', 'BJT-3', 'single', 'お客様に「調べた結果を報告します」を謙譲語で伝えると？
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (83300028, '調べた結果をご報告します。', 'Tôi sẽ báo cáo kết quả tìm hiểu ạ. (ご報告します — OK)', FALSE, 1);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (83300028, '調べました結果をご報告いたします。', 'Tôi xin báo cáo kết quả tìm hiểu ạ. (ご報告いたす — trang trọng hơn)', FALSE, 2);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (83300028, 'お調べいたしました結果をご報告申し上げます。', 'Tôi xin kính báo kết quả đã tìm hiểu ạ. (お調べいたす + ご報告申し上げる — rất trang trọng)', FALSE, 3);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (83300028, '状況に応じて A・B・C 全て使える', 'Tùy tình huống, cả A, B, C đều dùng được', TRUE, 4);
INSERT INTO questions (id, user_id, is_system, is_khoa_cu, question_type, content_type, level, selection_type, question, passage, passage_translation, general_explanation, skill_category, base_difficulty, tenant_id, is_active, is_deleted, created_at, created_by) VALUES (83300029, NULL, TRUE, FALSE, 'chon_dap_an', 'keigo_baitap_keigo_phan_loai', 'BJT-3', 'single', '「ご迷惑をおかけしました」より丁寧な謝罪表現はどれですか？
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (83300029, 'すみませんでした。', 'Xin lỗi ạ. (thông thường — kém trang trọng hơn)', FALSE, 1);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (83300029, 'ご迷惑をおかけいたしました。', 'Tôi đã gây phiền phức cho quý vị. (おかけいたす — trang trọng hơn)', FALSE, 2);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (83300029, '多大なるご迷惑をおかけいたしましたことを、深くお詫び申し上げます。', 'Tôi xin thành thật xin lỗi vì đã gây ra sự phiền phức lớn cho quý vị. (最高敬語)', FALSE, 3);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (83300029, 'B と C の両方が「ご迷惑をおかけしました」より丁寧', 'Cả B và C đều trang trọng hơn câu gốc', TRUE, 4);
INSERT INTO questions (id, user_id, is_system, is_khoa_cu, question_type, content_type, level, selection_type, question, passage, passage_translation, general_explanation, skill_category, base_difficulty, tenant_id, is_active, is_deleted, created_at, created_by) VALUES (83300030, NULL, TRUE, FALSE, 'chon_dap_an', 'keigo_baitap_keigo_phan_loai', 'BJT-3', 'single', '電話での会話を完成させてください。
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (83300030, '「お待ちして」/「いらっしゃって」', '「お待ちして」(Kenjougo: tôi đang chờ) / 「いらっしゃって」(Sonkeigo: mời ngài đến)', TRUE, 1);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (83300030, '「待って」/「来て」', '「待って」/ 「来て」(thông thường — không phù hợp)', FALSE, 2);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (83300030, '「待っておりまして」/「いらっしゃいまして」', '「待っておりまして」/ 「いらっしゃいまして」(sai ngữ pháp — ます形ではない)', FALSE, 3);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (83300030, '「お待ちして」/「お越しになって」', '「お待ちして」(Kenjougo) / 「お越しになって」(Sonkeigo — tự nhiên hơn)', FALSE, 4);
INSERT INTO questions (id, user_id, is_system, is_khoa_cu, question_type, content_type, level, selection_type, question, passage, passage_translation, general_explanation, skill_category, base_difficulty, tenant_id, is_active, is_deleted, created_at, created_by) VALUES (83300031, NULL, TRUE, FALSE, 'chon_dap_an', 'keigo_baitap_keigo_phan_loai', 'BJT-4', 'single', '次の文の中で、謙譲語の使い方が正しいものはどれですか？（全てお客様との会話）
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (83300031, 'お客様がいただきました。', 'Khách hàng đã nhận ạ. (いただく = Kenjougo — sai chủ ngữ, phải dùng くださる)', FALSE, 1);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (83300031, '弊社の田中が参ります。', 'Tanaka bên chúng tôi sẽ đến ạ. (参る = Kenjougo — đúng)', TRUE, 2);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (83300031, 'お客様が伺いました。', 'Khách hàng đã đến thăm ạ. (伺う = Kenjougo — sai chủ ngữ, phải dùng いらっしゃる)', FALSE, 3);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (83300031, 'お客様が申しました。', 'Khách hàng đã nói ạ. (申す = Kenjougo — sai chủ ngữ, phải dùng おっしゃる)', FALSE, 4);
INSERT INTO questions (id, user_id, is_system, is_khoa_cu, question_type, content_type, level, selection_type, question, passage, passage_translation, general_explanation, skill_category, base_difficulty, tenant_id, is_active, is_deleted, created_at, created_by) VALUES (83300032, NULL, TRUE, FALSE, 'chon_dap_an', 'keigo_baitap_keigo_phan_loai', 'BJT-4', 'single', '「させていただく」の使い方について、正しい説明はどれですか？
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (83300032, 'どんな動詞にも自由につけてよい', 'Có thể gắn tự do vào bất kỳ động từ nào', FALSE, 1);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (83300032, '相手の許可や恩恵を受けた上で自分が行動する時に使う。使い過ぎは不自然', 'Dùng khi bản thân hành động nhờ sự cho phép/ơn của đối phương. Dùng quá nhiều sẽ không tự nhiên', TRUE, 2);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (83300032, '尊敬語なので、相手の行動を説明する時に使う', 'Là Sonkeigo nên dùng khi mô tả hành động của đối phương', FALSE, 3);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (83300032, '「ご〜させていただく」の形は常に正しい', 'Dạng「ご〜させていただく」luôn luôn đúng', FALSE, 4);
INSERT INTO questions (id, user_id, is_system, is_khoa_cu, question_type, content_type, level, selection_type, question, passage, passage_translation, general_explanation, skill_category, base_difficulty, tenant_id, is_active, is_deleted, created_at, created_by) VALUES (83300033, NULL, TRUE, FALSE, 'chon_dap_an', 'keigo_baitap_keigo_phan_loai', 'BJT-4', 'single', 'あなたはA社員。B社のお客様（田中様）に、C社（第三者）の担当者について話す場面。「C社の鈴木さんが来ると言っていた」を正しい敬語にすると？
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (83300033, 'C社の鈴木さんが参ると申しておりました。', 'Anh Suzuki C nói rằng tôi sẽ đến. (参る + 申す = Kenjougo — SAI vì Suzuki không phải Uchi)', FALSE, 1);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (83300033, 'C社の鈴木様がいらっしゃると伺っております。', 'Tôi được biết ông Suzuki C sẽ đến ạ. (いらっしゃる = Sonkeigo cho Suzuki + 伺う = Kenjougo cho MÌNH biết)', FALSE, 2);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (83300033, 'C社の鈴木さんがいらっしゃると言っておりました。', 'Anh Suzuki C nói rằng ngài ấy sẽ đến. (いらっしゃる = Sonkeigo ✅, 言っておりました — tương đối)', FALSE, 3);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (83300033, 'B が最も正確で丁寧', 'B chính xác và lịch sự nhất', TRUE, 4);
INSERT INTO questions (id, user_id, is_system, is_khoa_cu, question_type, content_type, level, selection_type, question, passage, passage_translation, general_explanation, skill_category, base_difficulty, tenant_id, is_active, is_deleted, created_at, created_by) VALUES (83300034, NULL, TRUE, FALSE, 'chon_dap_an', 'keigo_baitap_keigo_phan_loai', 'BJT-4', 'single', '次のメール文で、下線部に誤りがあるものはどれですか？
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (83300034, '② ご送付いたしました', '② ご送付いたしました — Kenjougo của gửi', FALSE, 1);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (83300034, '③ ご不明な点がございましたら', '③ ご不明な点がございましたら', FALSE, 2);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (83300034, '④ 遠慮なく拝察ください', '④ 遠慮なく拝察ください — 拝察 là Kenjougo, không dùng để yêu cầu khách!', TRUE, 3);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (83300034, '⑤ 何卒よろしくお願い申し上げます', '⑤ 何卒よろしくお願い申し上げます', FALSE, 4);
INSERT INTO questions (id, user_id, is_system, is_khoa_cu, question_type, content_type, level, selection_type, question, passage, passage_translation, general_explanation, skill_category, base_difficulty, tenant_id, is_active, is_deleted, created_at, created_by) VALUES (83300035, NULL, TRUE, FALSE, 'chon_dap_an', 'keigo_baitap_keigo_phan_loai', 'BJT-4', 'single', '「申す」と「申し上げる」の違いについて正しい説明はどれですか？
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (83300035, '全く同じ意味で、使い分けは不要', 'Hoàn toàn giống nhau, không cần phân biệt', FALSE, 1);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (83300035, '「申し上げる」は「申す」より丁寧で、重要な場面や文書で使う', '「申し上げる」trang trọng hơn 申す — dùng trong các tình huống quan trọng hoặc văn bản chính thức', TRUE, 2);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (83300035, '「申す」は尊敬語、「申し上げる」は謙譲語', '「申す」là Sonkeigo, 「申し上げる」là Kenjougo', FALSE, 3);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (83300035, '「申し上げる」は二重敬語なので使ってはいけない', '「申し上げる」là 二重敬語 nên không được dùng', FALSE, 4);
INSERT INTO questions (id, user_id, is_system, is_khoa_cu, question_type, content_type, level, selection_type, question, passage, passage_translation, general_explanation, skill_category, base_difficulty, tenant_id, is_active, is_deleted, created_at, created_by) VALUES (83300036, NULL, TRUE, FALSE, 'chon_dap_an', 'keigo_baitap_keigo_phan_loai', 'BJT-4', 'single', '「ご多忙中にもかかわらず、ご参加いただきまして、誠にありがとうございました」の分析として正しいのはどれですか？
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (83300036, '「ご参加」は尊敬語、「いただきまして」は謙譲語で、組み合わせて使うのは正しい', '「ご参加」là Sonkeigo, 「いただきまして」là Kenjougo — kết hợp như vậy là đúng', TRUE, 1);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (83300036, '「ご参加いただく」全体が謙譲語', '「ご参加いただく」toàn bộ là Kenjougo', FALSE, 2);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (83300036, '「ご多忙中」は謙譲語なので、この文は間違い', '「ご多忙中」là Kenjougo nên câu này sai', FALSE, 3);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (83300036, '「ご参加」は謙譲語で、「いただきまして」は尊敬語', '「ご参加」là Kenjougo, 「いただきまして」là Sonkeigo', FALSE, 4);
INSERT INTO questions (id, user_id, is_system, is_khoa_cu, question_type, content_type, level, selection_type, question, passage, passage_translation, general_explanation, skill_category, base_difficulty, tenant_id, is_active, is_deleted, created_at, created_by) VALUES (83300037, NULL, TRUE, FALSE, 'chon_dap_an', 'keigo_baitap_keigo_phan_loai', 'BJT-4', 'single', 'クレーム対応で「担当者が調べて連絡します」を最も丁寧な謙譲語に直すと？
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (83300037, '担当者が調べて連絡します。', 'Nhân viên phụ trách sẽ tìm hiểu và liên hệ. (thông thường)', FALSE, 1);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (83300037, '担当の者が確認の上、改めてご連絡いたします。', 'Nhân viên phụ trách sẽ xác nhận rồi liên hệ lại ạ. (Kenjougo — chuẩn)', FALSE, 2);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (83300037, '担当の者よりご連絡申し上げます。', 'Nhân viên phụ trách sẽ liên hệ ạ. (申し上げる — trang trọng)', FALSE, 3);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (83300037, 'B が最も実用的でビジネス的', 'B thực dụng và kinh doanh nhất', TRUE, 4);
INSERT INTO questions (id, user_id, is_system, is_khoa_cu, question_type, content_type, level, selection_type, question, passage, passage_translation, general_explanation, skill_category, base_difficulty, tenant_id, is_active, is_deleted, created_at, created_by) VALUES (83300038, NULL, TRUE, FALSE, 'chon_dap_an', 'keigo_baitap_keigo_phan_loai', 'BJT-4', 'single', '次の会話で、下線部の敬語が不適切なものを選んでください。
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (83300038, '① ご来社いただき', '① ご来社いただき', FALSE, 1);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (83300038, '② ご説明いたします', '② ご説明いたします', FALSE, 2);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (83300038, '③ 伺ってください', '③ 伺ってください — 伺う là Kenjougo của MÌNH, yêu cầu khách ''伺う'' là sai!', TRUE, 3);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (83300038, '④ お持ちいたします', '④ お持ちいたします', FALSE, 4);
INSERT INTO questions (id, user_id, is_system, is_khoa_cu, question_type, content_type, level, selection_type, question, passage, passage_translation, general_explanation, skill_category, base_difficulty, tenant_id, is_active, is_deleted, created_at, created_by) VALUES (83300039, NULL, TRUE, FALSE, 'chon_dap_an', 'keigo_baitap_keigo_phan_loai', 'BJT-4', 'single', '取引先への正式なお礼状の書き方として、最も適切な文はどれですか？
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (83300039, '先日はいろいろとお世話になりました。ありがとうございました。', 'Hôm trước được quý vị giúp đỡ nhiều. Cảm ơn. (thông thường, không đủ trang trọng)', FALSE, 1);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (83300039, '先日は格別のご厚情を賜り、厚く御礼申し上げます。', 'Hôm trước được nhận ân tình đặc biệt, xin kính bày tỏ lòng biết ơn sâu sắc. (賜る + 御礼申し上げる)', TRUE, 2);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (83300039, '先日はお世話になり、お礼を言いたいと思います。', 'Hôm trước được giúp đỡ, tôi muốn nói lời cảm ơn. (quá thẳng thắn, thiếu trang trọng)', FALSE, 3);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (83300039, '先日のご支援に感謝いたします。今後ともよろしくお願いいたします。', 'Cảm ơn sự hỗ trợ hôm trước. Kính mong tiếp tục hợp tác. (Kenjougo đúng, đơn giản hơn B)', FALSE, 4);
INSERT INTO questions (id, user_id, is_system, is_khoa_cu, question_type, content_type, level, selection_type, question, passage, passage_translation, general_explanation, skill_category, base_difficulty, tenant_id, is_active, is_deleted, created_at, created_by) VALUES (83300040, NULL, TRUE, FALSE, 'chon_dap_an', 'keigo_baitap_keigo_phan_loai', 'BJT-4', 'single', '次のうち、ビジネス敬語として最も完成度が高い文はどれですか？
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (83300040, 'ご不便をおかけして申し訳なかったです。次は気をつけます。', 'Xin lỗi vì đã gây bất tiện. Lần sau tôi sẽ cẩn thận hơn. (thiếu trang trọng, nghe thô)', FALSE, 1);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (83300040, 'この度はご不便をおかけいたしまして、誠に申し訳ございませんでした。再発防止に努めてまいります。', 'Lần này thực sự xin lỗi vì đã gây bất tiện ạ. Chúng tôi sẽ cố gắng ngăn tái diễn. (Kenjougo đầy đủ)', TRUE, 2);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (83300040, '不便をかけてすみませんでした。気をつけます。', 'Xin lỗi đã gây bất tiện. Tôi sẽ cẩn thận. (thông thường — không phù hợp)', FALSE, 3);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (83300040, 'ご不便をおかけしてしまい、本当に申し訳ありません。', 'Thực sự xin lỗi vì đã gây bất tiện. (đủ lịch sự nhưng ít trang trọng hơn B)', FALSE, 4);
