INSERT INTO questions (id, user_id, is_system, is_khoa_cu, question_type, content_type, level, selection_type, question, passage, passage_translation, general_explanation, skill_category, base_difficulty, tenant_id, is_active, is_deleted, created_at, created_by) VALUES (84100031, NULL, TRUE, FALSE, 'chon_dap_an', 'keigo_baitap_juzu_doushi', 'BJT-4', 'single', '次の文の誤りを指摘してください。「お客様、こちらの資料をあげますので、お持ちください。」
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (84100031, '「お持ちください」が間違い', NULL, FALSE, 1);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (84100031, '「あげます」が間違い、「さしあげます」にすべき', NULL, TRUE, 2);
