INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (84100031, '「お客様」の呼びかけが間違い', NULL, FALSE, 4);
INSERT INTO questions (id, user_id, is_system, is_khoa_cu, question_type, content_type, level, selection_type, question, passage, passage_translation, general_explanation, skill_category, base_difficulty, tenant_id, is_active, is_deleted, created_at, created_by) VALUES (84100032, NULL, TRUE, FALSE, 'chon_dap_an', 'keigo_baitap_juzu_doushi', 'BJT-4', 'single', '次の文の誤りを指摘してください。「昨日、社長が私に賞状をくれました。とてもうれしかったです。」
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (84100032, '「とてもうれしかったです」が間違い', NULL, FALSE, 1);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (84100032, '「くれました」が間違い、「くださいました」にすべき', NULL, TRUE, 2);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (84100032, '「賞状を」が間違い', NULL, FALSE, 3);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (84100032, '「昨日」が間違い、「先日」にすべき', NULL, FALSE, 4);
INSERT INTO questions (id, user_id, is_system, is_khoa_cu, question_type, content_type, level, selection_type, question, passage, passage_translation, general_explanation, skill_category, base_difficulty, tenant_id, is_active, is_deleted, created_at, created_by) VALUES (84100033, NULL, TRUE, FALSE, 'chon_dap_an', 'keigo_baitap_juzu_doushi', 'BJT-4', 'single', '「ご支援を賜り、厚く御礼申し上げます」の「賜り（たまわり）」の意味と使用場面として正しいものはどれですか？
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (84100033, '「あげる」の謙譲語で、日常会話でよく使われる', NULL, FALSE, 1);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (84100033, '「もらう・いただく」のさらに上の謙譲語で、公式文書・挨拶状で使われる', NULL, TRUE, 2);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (84100033, '「くれる・くださる」と同じ意味で、話し言葉でも使える', NULL, FALSE, 3);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (84100033, '「やる」の丁寧語で、目下の人に使う', NULL, FALSE, 4);
INSERT INTO questions (id, user_id, is_system, is_khoa_cu, question_type, content_type, level, selection_type, question, passage, passage_translation, general_explanation, skill_category, base_difficulty, tenant_id, is_active, is_deleted, created_at, created_by) VALUES (84100034, NULL, TRUE, FALSE, 'chon_dap_an', 'keigo_baitap_juzu_doushi', 'BJT-4', 'single', '「させていただく」の使い方として最も不自然なものはどれですか？
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (84100034, 'では、資料をご説明させていただきます。', NULL, FALSE, 1);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (84100034, '明日から育児休暇を取得させていただきます。', NULL, FALSE, 2);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (84100034, '田中と申させていただきます。', NULL, TRUE, 3);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (84100034, '本日はよいお天気でございますね。', NULL, FALSE, 4);
INSERT INTO questions (id, user_id, is_system, is_khoa_cu, question_type, content_type, level, selection_type, question, passage, passage_translation, general_explanation, skill_category, base_difficulty, tenant_id, is_active, is_deleted, created_at, created_by) VALUES (84100035, NULL, TRUE, FALSE, 'chon_dap_an', 'keigo_baitap_juzu_doushi', 'BJT-4', 'single', '「私は弟に英語を教えてあげた。／弟は私に英語を教えてもらった。／弟が私に英語を教えてくれた。」3つの文の中で意味が【異なる】ものはどれですか？
