INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (84100035, '③だけが異なる', NULL, TRUE, 2);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (84100035, '①と②は同じ意味、③だけが異なる', NULL, FALSE, 3);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (84100035, '3つとも異なる意味', NULL, FALSE, 4);
INSERT INTO questions (id, user_id, is_system, is_khoa_cu, question_type, content_type, level, selection_type, question, passage, passage_translation, general_explanation, skill_category, base_difficulty, tenant_id, is_active, is_deleted, created_at, created_by) VALUES (84100036, NULL, TRUE, FALSE, 'chon_dap_an', 'keigo_baitap_juzu_doushi', 'BJT-4', 'single', '取引先から不当な要求をされ、断る場面。最も適切な断り方はどれですか？
