INSERT INTO questions (id, user_id, is_system, is_khoa_cu, question_type, content_type, level, selection_type, question, passage, passage_translation, general_explanation, skill_category, base_difficulty, tenant_id, is_active, is_deleted, created_at, created_by) VALUES (84200001, NULL, TRUE, FALSE, 'reading', 'keigo_dokkai_juzu_doushi', NULL, 'single', '「先日の営業事例の説明をしていただき」で使われている「いただく」は、誰が誰に何をしたことを表していますか。
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (84200001, '佐藤さんが山田課長に説明をした', NULL, FALSE, 1);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (84200001, '山田課長が佐藤さんに説明をした', NULL, TRUE, 2);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (84200001, '顧客が佐藤さんに説明をした', NULL, FALSE, 3);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (84200001, '佐藤さんが顧客に説明をした', NULL, FALSE, 4);
INSERT INTO questions (id, user_id, is_system, is_khoa_cu, question_type, content_type, level, selection_type, question, passage, passage_translation, general_explanation, skill_category, base_difficulty, tenant_id, is_active, is_deleted, created_at, created_by) VALUES (84200002, NULL, TRUE, FALSE, 'reading', 'keigo_dokkai_juzu_doushi', NULL, 'single', '「課長がわかりやすく教えてくださった」と「説明をしていただき」の二つの表現の違いは何ですか。
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (84200002, 'くださるは下の人が上の人を敬う表現で、いただくは上の人が下の人を敬う表現', NULL, FALSE, 1);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (84200002, 'どちらも同じ意味で、文体の違いだけ', NULL, FALSE, 2);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (84200002, 'くださるは「上の人が下の人にしてくれる」を表し、いただくは「下の人が上の人からの行為を受ける」を表す', NULL, TRUE, 3);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (84200002, 'いただくは「もらう」という意味で、くださるは「与える」という意味', NULL, FALSE, 4);
