INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (84200003, '佐藤さんが山田課長より上の立場にある', NULL, FALSE, 1);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (84200003, '山田課長が佐藤さんより高い立場にあり、親切に助けている', NULL, TRUE, 2);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (84200003, '二人は同じ立場で、相互に協力している', NULL, FALSE, 3);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (84200003, '山田課長と佐藤さんは初めて会った', NULL, FALSE, 4);
INSERT INTO questions (id, user_id, is_system, is_khoa_cu, question_type, content_type, level, selection_type, question, passage, passage_translation, general_explanation, skill_category, base_difficulty, tenant_id, is_active, is_deleted, created_at, created_by) VALUES (84200004, NULL, TRUE, FALSE, 'reading', 'keigo_dokkai_juzu_doushi', NULL, 'single', 'もし文中の「教えてくださった」を「教えてあげた」に変えたら、この文はどのような印象になりますか。
