INSERT INTO questions (id, user_id, is_system, is_khoa_cu, question_type, content_type, level, selection_type, question, passage, passage_translation, general_explanation, skill_category, base_difficulty, tenant_id, is_active, is_deleted, created_at, created_by) VALUES (84200008, NULL, TRUE, FALSE, 'reading', 'keigo_dokkai_juzu_doushi', NULL, 'single', '「トレーニングを実施していただける時間をお作りいただけますでしょうか」という長い表現は、実質的にはどのような依頼を表していますか。
