INSERT INTO questions (id, user_id, is_system, is_khoa_cu, question_type, content_type, level, selection_type, question, passage, passage_translation, general_explanation, skill_category, base_difficulty, tenant_id, is_active, is_deleted, created_at, created_by) VALUES (84200009, NULL, TRUE, FALSE, 'reading', 'keigo_dokkai_juzu_doushi', NULL, 'single', 'A社様が「この修正案で進めていただきたい」と言った時、誰が誰に何をするということを求めていますか。
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (84200009, 'A社が青山さんの会社に、修正案で進めることを許可している', NULL, FALSE, 1);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (84200009, 'A社が青山さんの会社に対して、修正案で進めることを依頼・許可している', NULL, TRUE, 2);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (84200009, '青山さんの会社がA社に修正案の実行を強要している', NULL, FALSE, 3);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (84200009, 'A社がA社自身で修正案を進めることを宣言している', NULL, FALSE, 4);
INSERT INTO questions (id, user_id, is_system, is_khoa_cu, question_type, content_type, level, selection_type, question, passage, passage_translation, general_explanation, skill_category, base_difficulty, tenant_id, is_active, is_deleted, created_at, created_by) VALUES (84200010, NULL, TRUE, FALSE, 'reading', 'keigo_dokkai_juzu_doushi', NULL, 'single', '「弊社の企画部門がプロジェクト案を修正させていただきました」という表現で、「させていただく」が使われている理由として、最も適切なのはどれですか。
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (84200010, '修正権が自社にあるので、自分たちが修正したことを主張するため', NULL, FALSE, 1);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (84200010, '顧客や上司の許可・指示のもとで修正行為を行ったことへの感謝と敬意を示すため', NULL, TRUE, 2);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (84200010, '修正案は失敗する可能性が高いので、事前に言い訳するため', NULL, FALSE, 3);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (84200010, '修正は簡単な作業なので、丁寧に言う必要がない', NULL, FALSE, 4);
INSERT INTO questions (id, user_id, is_system, is_khoa_cu, question_type, content_type, level, selection_type, question, passage, passage_translation, general_explanation, skill_category, base_difficulty, tenant_id, is_active, is_deleted, created_at, created_by) VALUES (84200011, NULL, TRUE, FALSE, 'reading', 'keigo_dokkai_juzu_doushi', NULL, 'single', '「施工業者に対して当初の契約内容変更手続きをさせていただきたく、お力添えをいただければ幸いです」という文から、青山さんの意図として最も正確なのはどれですか。
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (84200011, '青山さんが施工業者を支配下に置こうとしている', NULL, FALSE, 1);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (84200011, '青山さんが上司に依頼し、契約変更を実行する許可と支援を求めている', NULL, TRUE, 2);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (84200011, '施工業者に対して上司から権力を借りて、命令を下したいと言っている', NULL, FALSE, 3);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (84200011, '青山さんが契約変更について全責任を取る申し出', NULL, FALSE, 4);
INSERT INTO questions (id, user_id, is_system, is_khoa_cu, question_type, content_type, level, selection_type, question, passage, passage_translation, general_explanation, skill_category, base_difficulty, tenant_id, is_active, is_deleted, created_at, created_by) VALUES (84200012, NULL, TRUE, FALSE, 'reading', 'keigo_dokkai_juzu_doushi', NULL, 'single', '報告書全体を通じて、「いただく」や「させていただく」を繰り返し使うことで、青山さんはどのような態度を表現していますか。
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (84200012, 'すべての問題を上司のせいにして、責任を逃げようとしている', NULL, FALSE, 1);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (84200012, '自分たちの仕事の成功は、上司の指導と支援があってこそだと認識し、謙虚な姿勢で報告している', NULL, TRUE, 2);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (84200012, '上司を褒めるために、過度にへりくだって表現している', NULL, FALSE, 3);
