INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (84200013, 'A社がB社にお願いし、B社がC社にお願いする一方向の関係', NULL, FALSE, 1);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (84200013, 'B社がA社にお願いし、A社がC社にお願いする別の一方向の関係', NULL, FALSE, 2);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (84200013, 'A社とB社が協力してC社に対してお願いする関係で、最終的には顧客の要望を満たすための協力構造', NULL, TRUE, 3);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (84200013, 'C社が全て決定権を持っていて、他の二社はそれに従うだけ', NULL, FALSE, 4);
