INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (84200014, 'どちらも敬意を持って相手の行動を説明しており、B社とC社の双方が主体的に行動していることを示している', NULL, TRUE, 1);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (84200014, 'どちらも同じ授受動詞を使っているため、意味が全く同じ', NULL, FALSE, 2);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (84200014, 'B社の行動はC社の決定によって制約されている従属関係を表している', NULL, FALSE, 3);
