INSERT INTO questions (id, user_id, is_system, is_khoa_cu, question_type, content_type, level, selection_type, question, passage, passage_translation, general_explanation, skill_category, base_difficulty, tenant_id, is_active, is_deleted, created_at, created_by) VALUES (85100001, NULL, TRUE, FALSE, 'chon_dap_an', 'keigo_baitap_uchi_soto', 'BJT-1', 'single', '日本語の敬語における「内（うち）」と「外（そと）」の説明として正しいものはどれですか？
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (85100001, '「内」は自分より目上の人、「外」は自分より目下の人', NULL, FALSE, 1);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (85100001, '「内」は自分が属するグループ（自分・家族・自社など）、「外」はそのグループ外の人', NULL, TRUE, 2);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (85100001, '「内」は会社の上司、「外」は会社の部下', NULL, FALSE, 3);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (85100001, '「内」は親しい友人、「外」は知らない人', NULL, FALSE, 4);
INSERT INTO questions (id, user_id, is_system, is_khoa_cu, question_type, content_type, level, selection_type, question, passage, passage_translation, general_explanation, skill_category, base_difficulty, tenant_id, is_active, is_deleted, created_at, created_by) VALUES (85100002, NULL, TRUE, FALSE, 'chon_dap_an', 'keigo_baitap_uchi_soto', 'BJT-1', 'single', 'あなたが会社の社員（B社勤務）のとき、「内（uchi）」に含まれる人をすべて選んでください。
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (85100002, '自分・同僚・直属の上司・自社の社長', NULL, TRUE, 1);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (85100002, '自分・自社の同僚・取引先のお客様', NULL, FALSE, 2);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (85100002, '自分・友人・他社の社員', NULL, FALSE, 3);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (85100002, '自分だけ', NULL, FALSE, 4);
INSERT INTO questions (id, user_id, is_system, is_khoa_cu, question_type, content_type, level, selection_type, question, passage, passage_translation, general_explanation, skill_category, base_difficulty, tenant_id, is_active, is_deleted, created_at, created_by) VALUES (85100003, NULL, TRUE, FALSE, 'chon_dap_an', 'keigo_baitap_uchi_soto', 'BJT-1', 'single', '内外のルールに従うと、外の人（お客様）に対して話す時、内の人（自社の上司）についてはどのように話すべきですか？
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (85100003, '上司なので尊敬語を使って敬意を示す', NULL, FALSE, 1);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (85100003, '上司への敬意をお客様にも示すため、最高の敬語を使う', NULL, FALSE, 2);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (85100003, '内の人として扱い、敬語を外し、謙譲語または普通語で話す', NULL, TRUE, 3);
