INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (85100029, '別の会社なので常に「外（soto）」', NULL, FALSE, 2);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (85100029, '状況と文脈によるが、一般的には「外（soto）」として扱うのが安全', NULL, TRUE, 3);
