INSERT INTO questions (id, user_id, is_system, is_khoa_cu, question_type, content_type, level, selection_type, question, passage, passage_translation, general_explanation, skill_category, base_difficulty, tenant_id, is_active, is_deleted, created_at, created_by) VALUES (85200001, NULL, TRUE, FALSE, 'reading', 'keigo_dokkai_uchi_soto', NULL, 'single', 'この会話で、受付者が田中についての正しい表現はどれですか。
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (85200001, '田中さんは只今席を外しております。', NULL, FALSE, 1);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (85200001, '田中は只今席を外しております。', NULL, TRUE, 2);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (85200001, '田中先生は只今席を外しております。', NULL, FALSE, 3);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (85200001, '田中さまは只今席を外しております。', NULL, FALSE, 4);
INSERT INTO questions (id, user_id, is_system, is_khoa_cu, question_type, content_type, level, selection_type, question, passage, passage_translation, general_explanation, skill_category, base_difficulty, tenant_id, is_active, is_deleted, created_at, created_by) VALUES (85200002, NULL, TRUE, FALSE, 'reading', 'keigo_dokkai_uchi_soto', NULL, 'single', '受付者が「田中に（　）をお預かりすることはできますか」と言った場合、（　）に入る正しい言葉は？
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (85200002, 'ご伝言', NULL, TRUE, 1);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (85200002, '伝言', NULL, FALSE, 2);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (85200002, 'お言葉', NULL, FALSE, 3);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (85200002, 'ご指示', NULL, FALSE, 4);
INSERT INTO questions (id, user_id, is_system, is_khoa_cu, question_type, content_type, level, selection_type, question, passage, passage_translation, general_explanation, skill_category, base_difficulty, tenant_id, is_active, is_deleted, created_at, created_by) VALUES (85200003, NULL, TRUE, FALSE, 'reading', 'keigo_dokkai_uchi_soto', NULL, 'single', 'もし受付者が他の担当者に代わる場合、以下の表現のどれが間違っていますか。
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (85200003, '他の担当者に代わることができます。', NULL, FALSE, 1);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (85200003, '別の担当の山田さんにお繋ぎいたします。', NULL, TRUE, 2);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (85200003, '弊社の山田がお取り次ぎいたします。', NULL, FALSE, 3);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (85200003, '山田課長がお電話させていただきます。', NULL, FALSE, 4);
INSERT INTO questions (id, user_id, is_system, is_khoa_cu, question_type, content_type, level, selection_type, question, passage, passage_translation, general_explanation, skill_category, base_difficulty, tenant_id, is_active, is_deleted, created_at, created_by) VALUES (85200004, NULL, TRUE, FALSE, 'reading', 'keigo_dokkai_uchi_soto', NULL, 'single', '次の文で敬語の使い方に誤りがあるのはどれですか。「何かご不明な点がございましたら、いつでもお気軽にお問い合わせください。」
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (85200004, 'ご不明な点 — tôn kính đúng cho Soto', NULL, FALSE, 1);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (85200004, 'ございました — tôn kính quá mức', NULL, FALSE, 2);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (85200004, 'お気軽に — biểu hiện tôn kính khách hàng', NULL, FALSE, 3);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (85200004, 'お問い合わせください — yêu cầu khách hàng liên hệ', NULL, TRUE, 4);
INSERT INTO questions (id, user_id, is_system, is_khoa_cu, question_type, content_type, level, selection_type, question, passage, passage_translation, general_explanation, skill_category, base_difficulty, tenant_id, is_active, is_deleted, created_at, created_by) VALUES (85200005, NULL, TRUE, FALSE, 'reading', 'keigo_dokkai_uchi_soto', NULL, 'single', 'このメールの主な目的は何ですか。
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (85200005, '自社の製品について説明するため', NULL, FALSE, 1);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (85200005, '訪問予定者の変更を知らせ、謝罪するため', NULL, TRUE, 2);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (85200005, '相手方の都合を変更してもらうため', NULL, FALSE, 3);
