INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (87100017, '担当者はいらっしゃいません。', 'Người phụ trách không có ở đây.', FALSE, 3);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (87100017, '担当者は外出されております。', 'Người phụ trách đã ra ngoài (Sonkeigo).', FALSE, 4);
INSERT INTO questions (id, user_id, is_system, is_khoa_cu, question_type, content_type, level, selection_type, question, passage, passage_translation, general_explanation, skill_category, base_difficulty, tenant_id, is_active, is_deleted, created_at, created_by) VALUES (87100018, NULL, TRUE, FALSE, 'chon_dap_an', 'keigo_baitap_keigo_tong_hop', 'BJT-2', 'single', '「ご確認（　　）、ありがとうございます。」— 主語がお客様の場合、（　　）に入る正しい語は？
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (87100018, 'いただき', 'いただき (Kenjougo: tôi được nhận)', FALSE, 1);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (87100018, 'くださり', 'くださり (Sonkeigo: ngài đã cho/làm ơn)', TRUE, 2);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (87100018, 'なさり', 'なさり (Sonkeigo của する)', FALSE, 3);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (87100018, 'され', 'され (thụ động lịch sự)', FALSE, 4);
INSERT INTO questions (id, user_id, is_system, is_khoa_cu, question_type, content_type, level, selection_type, question, passage, passage_translation, general_explanation, skill_category, base_difficulty, tenant_id, is_active, is_deleted, created_at, created_by) VALUES (87100019, NULL, TRUE, FALSE, 'chon_dap_an', 'keigo_baitap_keigo_tong_hop', 'BJT-2', 'single', '「申し訳ありませんが、ただいま（　　）おります」— 「できない」の謙譲語は？
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (87100019, 'できなくて', 'できなくて (không thể — thô)', FALSE, 1);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (87100019, 'いたしかねて', 'いたしかねて (e rằng khó có thể — lịch sự)', TRUE, 2);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (87100019, 'しないで', 'しないで (không làm — thô)', FALSE, 3);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (87100019, 'なさらなくて', 'なさらなくて (Sonkeigo: ngài không làm)', FALSE, 4);
INSERT INTO questions (id, user_id, is_system, is_khoa_cu, question_type, content_type, level, selection_type, question, passage, passage_translation, general_explanation, skill_category, base_difficulty, tenant_id, is_active, is_deleted, created_at, created_by) VALUES (87100020, NULL, TRUE, FALSE, 'chon_dap_an', 'keigo_baitap_keigo_tong_hop', 'BJT-2', 'single', '社長のことをお客様に伝える時、「社長のお（　　）をお伝えします」— 正しい語は？
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (87100020, '言葉（ことば）', '言葉 (lời nói — thông thường)', FALSE, 1);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (87100020, '話（はなし）', '話 (câu chuyện)', FALSE, 2);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (87100020, '伝言（でんごん）', '伝言 (lời nhắn — thông thường)', FALSE, 3);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (87100020, '言葉（ことば）', 'お言葉 (lời — có tiền tố お lịch sự)', TRUE, 4);
INSERT INTO questions (id, user_id, is_system, is_khoa_cu, question_type, content_type, level, selection_type, question, passage, passage_translation, general_explanation, skill_category, base_difficulty, tenant_id, is_active, is_deleted, created_at, created_by) VALUES (87100021, NULL, TRUE, FALSE, 'chon_dap_an', 'keigo_baitap_keigo_tong_hop', 'BJT-3', 'single', 'お客様から「社長はいらっしゃいますか」と聞かれました。社長が席にいる場合、正しい答えはどれですか？
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (87100021, 'はい、社長はいらっしゃいます。', 'Vâng, giám đốc đang có ở đây ạ. (Sonkeigo)', FALSE, 1);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (87100021, 'はい、社長はおります。', 'Vâng, giám đốc đang có mặt. (Kenjougo)', TRUE, 2);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (87100021, 'はい、社長はいます。', 'Vâng, giám đốc đang có ở đây. (thông thường)', FALSE, 3);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (87100021, 'はい、社長はございます。', 'Vâng, giám đốc đang có ở đây. (sai — ございます cho đồ vật)', FALSE, 4);
INSERT INTO questions (id, user_id, is_system, is_khoa_cu, question_type, content_type, level, selection_type, question, passage, passage_translation, general_explanation, skill_category, base_difficulty, tenant_id, is_active, is_deleted, created_at, created_by) VALUES (87100022, NULL, TRUE, FALSE, 'chon_dap_an', 'keigo_baitap_keigo_tong_hop', 'BJT-3', 'single', '取引先に電話して、先方の担当者を呼ぶ時、正しい表現はどれですか？
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (87100022, '山田さんをお願いします。', 'Cho tôi gặp anh Yamada. (bình thường)', FALSE, 1);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (87100022, '山田様をお願いいたします。', 'Xin cho tôi gặp quý ông Yamada. (lịch sự)', TRUE, 2);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (87100022, '山田さんに来ていただけますか。', 'Anh Yamada có thể đến được không?', FALSE, 3);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (87100022, '山田様がいらっしゃいますか、お呼びします。', 'Quý ông Yamada có ở đó không, tôi sẽ gọi.', FALSE, 4);
INSERT INTO questions (id, user_id, is_system, is_khoa_cu, question_type, content_type, level, selection_type, question, passage, passage_translation, general_explanation, skill_category, base_difficulty, tenant_id, is_active, is_deleted, created_at, created_by) VALUES (87100023, NULL, TRUE, FALSE, 'chon_dap_an', 'keigo_baitap_keigo_tong_hop', 'BJT-3', 'single', '「先生が書いた本を読んだ」を最も丁寧な敬語にしてください。
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (87100023, '先生がお書きになった本を読みました。', 'Thầy đã viết cuốn sách, tôi đã đọc. (Sonkeigo cho thầy, thường cho mình)', FALSE, 1);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (87100023, '先生がお書きになった本を拝読いたしました。', 'Thầy đã viết cuốn sách, tôi đã kính đọc. (Sonkeigo + Kenjougo)', TRUE, 2);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (87100023, '先生が書かれた本をお読みいたしました。', 'Thầy đã viết (thụ động lịch sự), tôi đã đọc. (hỗn hợp)', FALSE, 3);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (87100023, '先生がお書きになった本を拝読なさいました。', 'Thầy đã đọc cuốn sách thầy viết. (sai chủ ngữ)', FALSE, 4);
INSERT INTO questions (id, user_id, is_system, is_khoa_cu, question_type, content_type, level, selection_type, question, passage, passage_translation, general_explanation, skill_category, base_difficulty, tenant_id, is_active, is_deleted, created_at, created_by) VALUES (87100024, NULL, TRUE, FALSE, 'chon_dap_an', 'keigo_baitap_keigo_tong_hop', 'BJT-3', 'single', 'メールの書き出しとして最も適切な表現はどれですか？
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (87100024, 'こんにちは。田中です。', 'Xin chào. Tôi là Tanaka.', FALSE, 1);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (87100024, 'お世話になっております。株式会社〇〇の田中でございます。', 'Cảm ơn sự quan tâm của quý vị. Tôi là Tanaka, công ty 〇〇.', TRUE, 2);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (87100024, 'はじめまして。田中と申します。', 'Rất vui được gặp lần đầu. Tôi tên là Tanaka.', FALSE, 3);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (87100024, '突然のメール失礼いたします。', 'Xin lỗi vì đã gửi email đột ngột.', FALSE, 4);
INSERT INTO questions (id, user_id, is_system, is_khoa_cu, question_type, content_type, level, selection_type, question, passage, passage_translation, general_explanation, skill_category, base_difficulty, tenant_id, is_active, is_deleted, created_at, created_by) VALUES (87100025, NULL, TRUE, FALSE, 'chon_dap_an', 'keigo_baitap_keigo_tong_hop', 'BJT-3', 'single', '電話を受けた時、相手の名前を確認する正しい表現はどれですか？
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (87100025, '名前は何ですか？', 'Tên bạn là gì?', FALSE, 1);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (87100025, 'あなたの名前を教えてください。', 'Hãy cho tôi biết tên bạn.', FALSE, 2);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (87100025, '失礼ですが、お名前をお聞かせいただけますか。', 'Xin lỗi, liệu quý vị có thể cho biết tên không ạ?', TRUE, 3);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (87100025, 'お名前はございますか。', 'Quý vị có tên không ạ? (sai ngữ nghĩa)', FALSE, 4);
INSERT INTO questions (id, user_id, is_system, is_khoa_cu, question_type, content_type, level, selection_type, question, passage, passage_translation, general_explanation, skill_category, base_difficulty, tenant_id, is_active, is_deleted, created_at, created_by) VALUES (87100026, NULL, TRUE, FALSE, 'chon_dap_an', 'keigo_baitap_keigo_tong_hop', 'BJT-3', 'single', '（　）に入る正しい語を選んでください。「明日、御社に（　）してもよろしいでしょうか。」
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (87100026, '訪問（ほうもん）', '訪問 (thăm — thông thường)', FALSE, 1);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (87100026, '伺い（うかがい）', '伺い (thăm/hỏi — Kenjougo)', TRUE, 2);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (87100026, 'お邪魔（おじゃま）', 'お邪魔 (làm phiền — thân mật)', FALSE, 3);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (87100026, 'いらっしゃい', 'いらっしゃい (Sonkeigo — sai chủ ngữ)', FALSE, 4);
INSERT INTO questions (id, user_id, is_system, is_khoa_cu, question_type, content_type, level, selection_type, question, passage, passage_translation, general_explanation, skill_category, base_difficulty, tenant_id, is_active, is_deleted, created_at, created_by) VALUES (87100027, NULL, TRUE, FALSE, 'chon_dap_an', 'keigo_baitap_keigo_tong_hop', 'BJT-3', 'single', '上司から食事に誘われた時、承諾する丁寧な表現はどれですか？
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (87100027, 'はい、行きます！', 'Vâng, tôi đi!', FALSE, 1);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (87100027, 'ありがとう、行くよ。', 'Cảm ơn, tôi đi nhé.', FALSE, 2);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (87100027, 'ぜひ、ご一緒させていただきます。', 'Nhất định rồi, tôi xin được đi cùng ạ.', TRUE, 3);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (87100027, '行ければと思います。', 'Tôi nghĩ có thể đi được.', FALSE, 4);
INSERT INTO questions (id, user_id, is_system, is_khoa_cu, question_type, content_type, level, selection_type, question, passage, passage_translation, general_explanation, skill_category, base_difficulty, tenant_id, is_active, is_deleted, created_at, created_by) VALUES (87100028, NULL, TRUE, FALSE, 'chon_dap_an', 'keigo_baitap_keigo_tong_hop', 'BJT-3', 'single', '「〜させていただく」の正しい使い方はどれですか？
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (87100028, '資料を確認させていただきました。', 'Tôi đã được phép xác nhận tài liệu ạ.', FALSE, 1);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (87100028, 'お客様に確認させていただきます。', 'Tôi sẽ để khách hàng xác nhận.', FALSE, 2);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (87100028, '社長に確認させていただきます。', 'Tôi sẽ xin phép được hỏi giám đốc xác nhận.', TRUE, 3);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (87100028, '確認させていただいてください。', 'Hãy để tôi được xác nhận. (mệnh lệnh — sai)', FALSE, 4);
INSERT INTO questions (id, user_id, is_system, is_khoa_cu, question_type, content_type, level, selection_type, question, passage, passage_translation, general_explanation, skill_category, base_difficulty, tenant_id, is_active, is_deleted, created_at, created_by) VALUES (87100029, NULL, TRUE, FALSE, 'chon_dap_an', 'keigo_baitap_keigo_tong_hop', 'BJT-3', 'single', '「あいにく」を使って断る時、最も自然な表現はどれですか？（日程の変更を断る場面）
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (87100029, 'あいにく、ダメです。', 'Tiếc là không được.', FALSE, 1);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (87100029, 'あいにく、その日は都合がつきかねます。', 'Thật tiếc, ngày đó tôi e rằng không thể sắp xếp được.', TRUE, 2);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (87100029, 'あいにく、行けません。', 'Tiếc là tôi không đi được.', FALSE, 3);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (87100029, 'あいにくですが、行かないです。', 'Thật tiếc nhưng tôi sẽ không đi.', FALSE, 4);
INSERT INTO questions (id, user_id, is_system, is_khoa_cu, question_type, content_type, level, selection_type, question, passage, passage_translation, general_explanation, skill_category, base_difficulty, tenant_id, is_active, is_deleted, created_at, created_by) VALUES (87100030, NULL, TRUE, FALSE, 'chon_dap_an', 'keigo_baitap_keigo_tong_hop', 'BJT-3', 'single', '会議の後、お客様に資料を渡す時、正しい表現はどれですか？
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (87100030, 'これ、持って行ってください。', 'Cầm cái này đi.', FALSE, 1);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (87100030, '資料をあげます。', 'Tôi cho anh tài liệu này.', FALSE, 2);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (87100030, 'こちら、資料でございます。どうぞお持ちください。', 'Đây là tài liệu ạ. Xin mời quý vị cầm về.', TRUE, 3);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (87100030, '資料を持って行っていただけますか。', 'Quý vị có thể mang tài liệu này đi không?', FALSE, 4);
INSERT INTO questions (id, user_id, is_system, is_khoa_cu, question_type, content_type, level, selection_type, question, passage, passage_translation, general_explanation, skill_category, base_difficulty, tenant_id, is_active, is_deleted, created_at, created_by) VALUES (87100031, NULL, TRUE, FALSE, 'chon_dap_an', 'keigo_baitap_keigo_tong_hop', 'BJT-4', 'single', '次の文の中で、敬語の使い方が正しいものはどれですか？（全てお客様との会話）
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (87100031, '社長は今、参っております。', 'Giám đốc hiện đang ở đây. (Kenjougo cho người trong nhóm)', FALSE, 1);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (87100031, '田中部長がいらっしゃいます。', 'Trưởng phòng Tanaka đang có mặt. (Sonkeigo cho người trong nhóm — SAI)', FALSE, 2);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (87100031, '弊社の山田が担当いたします。', 'Yamada bên tôi sẽ phụ trách. (Kenjougo — đúng)', TRUE, 3);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (87100031, '私どもの社長が申し上げました。', 'Giám đốc chúng tôi đã trình bày. (sai — 申し上げる dùng cho bản thân, không phải sếp)', FALSE, 4);
INSERT INTO questions (id, user_id, is_system, is_khoa_cu, question_type, content_type, level, selection_type, question, passage, passage_translation, general_explanation, skill_category, base_difficulty, tenant_id, is_active, is_deleted, created_at, created_by) VALUES (87100032, NULL, TRUE, FALSE, 'chon_dap_an', 'keigo_baitap_keigo_tong_hop', 'BJT-4', 'single', '「先生が書かれた論文を拝読なさいました」— この文の問題点は何ですか？
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (87100032, '「書かれた」が間違っている', '「書かれた」sai', FALSE, 1);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (87100032, '「拝読なさいました」の部分が間違っている — 主語の矛盾', '「拝読なさいました」sai — mâu thuẫn chủ ngữ', TRUE, 2);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (87100032, '「論文」の前に「ご」が必要', 'Cần thêm「ご」trước「論文」', FALSE, 3);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (87100032, '「先生」の後に「が」でなく「の」が正しい', 'Sau「先生」phải dùng「の」không phải「が」', FALSE, 4);
INSERT INTO questions (id, user_id, is_system, is_khoa_cu, question_type, content_type, level, selection_type, question, passage, passage_translation, general_explanation, skill_category, base_difficulty, tenant_id, is_active, is_deleted, created_at, created_by) VALUES (87100033, NULL, TRUE, FALSE, 'chon_dap_an', 'keigo_baitap_keigo_tong_hop', 'BJT-4', 'single', 'あなたはA社の社員です。B社のお客様に、自社の田中課長（あなたの上司）について話しています。正しい表現はどれですか？
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (87100033, '田中課長はただいまいらっしゃいません。', 'Trưởng phòng Tanaka hiện không có ở đây. (Sonkeigo — SAI)', FALSE, 1);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (87100033, '田中はただいま外出しております。', 'Tanaka hiện đang ra ngoài. (Kenjougo — ĐÚNG)', TRUE, 2);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (87100033, '田中課長はただいま外出されております。', 'Trưởng phòng Tanaka hiện đang ra ngoài. (Sonkeigo thụ động — SAI)', FALSE, 3);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (87100033, 'うちの田中課長は今外出なさっています。', 'Trưởng phòng Tanaka nhà tôi đang ra ngoài. (Sonkeigo — SAI)', FALSE, 4);
INSERT INTO questions (id, user_id, is_system, is_khoa_cu, question_type, content_type, level, selection_type, question, passage, passage_translation, general_explanation, skill_category, base_difficulty, tenant_id, is_active, is_deleted, created_at, created_by) VALUES (87100034, NULL, TRUE, FALSE, 'chon_dap_an', 'keigo_baitap_keigo_tong_hop', 'BJT-4', 'single', 'メールで「ご確認のほど、よろしくお願い申し上げます」と書く。この表現について正しい説明はどれですか？
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (87100034, '「ご確認」はKenjougo、「申し上げます」はSonkeigo', '「ご確認」là Kenjougo, 「申し上げます」là Sonkeigo', FALSE, 1);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (87100034, '「ご確認」はSonkeigo、「申し上げます」はKenjougo、全体として非常に丁寧な依頼表現', '「ご確認」là Sonkeigo, 「申し上げます」là Kenjougo — toàn câu là yêu cầu rất lịch sự', TRUE, 2);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (87100034, '「のほど」は不要で、省略できる', '「のほど」không cần thiết, có thể bỏ đi', FALSE, 3);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (87100034, '「申し上げます」はTeineigo', '「申し上げます」là Teineigo', FALSE, 4);
INSERT INTO questions (id, user_id, is_system, is_khoa_cu, question_type, content_type, level, selection_type, question, passage, passage_translation, general_explanation, skill_category, base_difficulty, tenant_id, is_active, is_deleted, created_at, created_by) VALUES (87100035, NULL, TRUE, FALSE, 'chon_dap_an', 'keigo_baitap_keigo_tong_hop', 'BJT-4', 'single', '電話中、相手が「田中部長はいますか？」と聞きました。田中部長は外出中です。最も適切な対応はどれですか？
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (87100035, '「田中部長はただいま外出されております。よろしければ、折り返しご連絡いただけますか。」', '(Sonkeigo cho sếp — SAI) + yêu cầu khách gọi lại', FALSE, 1);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (87100035, '「田中はただいま外出しております。よろしければ、ご伝言を承りましょうか。」', '(Kenjougo cho sếp — đúng) + hỏi có muốn nhắn lại không', TRUE, 2);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (87100035, '「田中はいません。後でかけ直してください。」', 'Tanaka không có. Vui lòng gọi lại sau.', FALSE, 3);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (87100035, '「田中部長はお出かけになっています。メッセージを残しますか？」', '(Sonkeigo cho sếp — SAI) + hỏi muốn để lại tin nhắn không', FALSE, 4);
INSERT INTO questions (id, user_id, is_system, is_khoa_cu, question_type, content_type, level, selection_type, question, passage, passage_translation, general_explanation, skill_category, base_difficulty, tenant_id, is_active, is_deleted, created_at, created_by) VALUES (87100036, NULL, TRUE, FALSE, 'chon_dap_an', 'keigo_baitap_keigo_tong_hop', 'BJT-4', 'single', '接待でお客様に食事をすすめる時、正しい表現はどれですか？
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (87100036, 'どうぞ、いただいてください。', 'Mời anh/chị dùng ạ. (いただく = Kenjougo — sai chủ ngữ)', FALSE, 1);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (87100036, 'どうぞ、召し上がってください。', 'Mời quý vị dùng ạ. (召し上がる = Sonkeigo — đúng)', TRUE, 2);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (87100036, 'どうぞ、食べてください。', 'Mời ăn nhé. (thông thường — không phù hợp)', FALSE, 3);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (87100036, 'どうぞ、お食べになってください。', 'Mời ngài ăn ạ. (cấu trúc sai — お食べになる không tự nhiên)', FALSE, 4);
INSERT INTO questions (id, user_id, is_system, is_khoa_cu, question_type, content_type, level, selection_type, question, passage, passage_translation, general_explanation, skill_category, base_difficulty, tenant_id, is_active, is_deleted, created_at, created_by) VALUES (87100037, NULL, TRUE, FALSE, 'chon_dap_an', 'keigo_baitap_keigo_tong_hop', 'BJT-4', 'single', 'メールで「先日お送りした資料、確認してもらえましたか？」を最も丁寧なビジネス敬語に直すと？
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (87100037, '先日送った資料、確認していただけましたか？', 'Tài liệu tôi gửi hôm trước, quý vị đã xem chưa?', FALSE, 1);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (87100037, '先日お送りいたしました資料は、ご確認いただけましたでしょうか。', 'Tài liệu tôi kính gửi hôm trước, quý vị đã xem qua chưa ạ?', TRUE, 2);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (87100037, '先日お送りした資料を、ご覧いただけましたでしょうか。', 'Tài liệu tôi gửi hôm trước, quý vị đã ngó qua chưa ạ?', FALSE, 3);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (87100037, '先日ご送付いたしました資料は、お確認なさいましたでしょうか。', 'Tài liệu tôi kính gửi hôm trước, quý vị đã xác nhận chưa ạ?', FALSE, 4);
INSERT INTO questions (id, user_id, is_system, is_khoa_cu, question_type, content_type, level, selection_type, question, passage, passage_translation, general_explanation, skill_category, base_difficulty, tenant_id, is_active, is_deleted, created_at, created_by) VALUES (87100038, NULL, TRUE, FALSE, 'chon_dap_an', 'keigo_baitap_keigo_tong_hop', 'BJT-4', 'single', '次の4つの表現を丁寧さの低い順に並べてください。「①いただけますか ②いただけないでしょうか ③てもらえますか ④てもらえない」
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (87100038, '④→③→①→②', '④ (thô nhất) → ③ → ① → ② (lịch sự nhất)', TRUE, 1);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (87100038, '③→④→①→②', '③ → ④ → ① → ②', FALSE, 2);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (87100038, '②→①→③→④', '② (lịch sự nhất) → ① → ③ → ④', FALSE, 3);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (87100038, '①→②→③→④', '① → ② → ③ → ④ (thô nhất)', FALSE, 4);
INSERT INTO questions (id, user_id, is_system, is_khoa_cu, question_type, content_type, level, selection_type, question, passage, passage_translation, general_explanation, skill_category, base_difficulty, tenant_id, is_active, is_deleted, created_at, created_by) VALUES (87100039, NULL, TRUE, FALSE, 'chon_dap_an', 'keigo_baitap_keigo_tong_hop', 'BJT-4', 'single', '会議中、上司の意見に同意する時、最も適切なビジネス表現はどれですか？
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (87100039, 'そうですね！全然いいと思います。', 'Đúng rồi! Tôi hoàn toàn thấy ổn.', FALSE, 1);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (87100039, 'おっしゃる通りでございます。', 'Đúng như ngài đã nói ạ.', TRUE, 2);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (87100039, '私もそう思います。', 'Tôi cũng nghĩ vậy.', FALSE, 3);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (87100039, 'それはいい考えですね。', 'Đó là ý kiến hay đấy nhỉ.', FALSE, 4);
INSERT INTO questions (id, user_id, is_system, is_khoa_cu, question_type, content_type, level, selection_type, question, passage, passage_translation, general_explanation, skill_category, base_difficulty, tenant_id, is_active, is_deleted, created_at, created_by) VALUES (87100040, NULL, TRUE, FALSE, 'chon_dap_an', 'keigo_baitap_keigo_tong_hop', 'BJT-4', 'single', '次の会話で、（　）に入る最も適切な表現はどれですか？
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (87100040, '説明します。', 'Tôi sẽ giải thích.', FALSE, 1);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (87100040, 'ご説明いたします。', 'Tôi xin được giải thích ạ.', TRUE, 2);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (87100040, '説明させてもらいます。', 'Để tôi giải thích nhé.', FALSE, 3);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (87100040, 'ご説明してあげます。', 'Tôi sẽ giải thích cho ngài. (あげる — kiêu ngạo)', FALSE, 4);
