INSERT INTO questions (id, user_id, is_system, is_khoa_cu, question_type, content_type, level, selection_type, question, passage, passage_translation, general_explanation, skill_category, base_difficulty, tenant_id, is_active, is_deleted, created_at, created_by) VALUES (87200001, NULL, TRUE, FALSE, 'reading', 'keigo_dokkai_keigo_tong_hop', NULL, 'single', '「資料を参考にさせていただき」の表現として最も適切な説明は？
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (87200001, '課長が私に資料を参考にするよう指示した', NULL, FALSE, 1);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (87200001, '私が資料を参考にしたことを課長に許可をもらった', NULL, TRUE, 2);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (87200001, '資料は私に参考にされてしまった', NULL, FALSE, 3);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (87200001, '課長が資料を参考にするのを手伝った', NULL, FALSE, 4);
INSERT INTO questions (id, user_id, is_system, is_khoa_cu, question_type, content_type, level, selection_type, question, passage, passage_translation, general_explanation, skill_category, base_difficulty, tenant_id, is_active, is_deleted, created_at, created_by) VALUES (87200002, NULL, TRUE, FALSE, 'reading', 'keigo_dokkai_keigo_tong_hop', NULL, 'single', '「ご送付いただき」と「を送ってもらい」を比較した場合、正しい説明は？
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (87200002, 'いただくは課長が主体で、もらうは私が主体で受け取る', NULL, FALSE, 1);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (87200002, '意味は同じだが、いただくはより敬語で丁寧な言い方である', NULL, TRUE, 2);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (87200002, 'いただくは過去完了で、もらうは現在進行である', NULL, FALSE, 3);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (87200002, '両方とも同じで、文法的に区別する必要がない', NULL, FALSE, 4);
INSERT INTO questions (id, user_id, is_system, is_khoa_cu, question_type, content_type, level, selection_type, question, passage, passage_translation, general_explanation, skill_category, base_difficulty, tenant_id, is_active, is_deleted, created_at, created_by) VALUES (87200003, NULL, TRUE, FALSE, 'reading', 'keigo_dokkai_keigo_tong_hop', NULL, 'single', '下線部「ご報告させていただきたく存じます」は「報告させられたく存じます」に置き換えられますか。その理由は？
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (87200003, 'できない。なぜなら「させられる」は不本意な強制を表すが、ここは「許可を求める」意味だから', NULL, TRUE, 1);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (87200003, 'できる。両方とも同じ意味である', NULL, FALSE, 2);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (87200003, 'できない。なぜなら「させられる」は過去形で、「させていただく」は未来形だから', NULL, FALSE, 3);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (87200003, 'できる。「させられる」はより丁寧な表現だから', NULL, FALSE, 4);
INSERT INTO questions (id, user_id, is_system, is_khoa_cu, question_type, content_type, level, selection_type, question, passage, passage_translation, general_explanation, skill_category, base_difficulty, tenant_id, is_active, is_deleted, created_at, created_by) VALUES (87200004, NULL, TRUE, FALSE, 'reading', 'keigo_dokkai_keigo_tong_hop', NULL, 'single', 'メール全体の送信者の態度として最も正確なものは？
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (87200004, '課長に不満があり、資料の品質に疑問を持っている', NULL, FALSE, 1);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (87200004, '課長に感謝し、資料を活用できたことを報告し、さらに指導を希望している', NULL, TRUE, 2);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (87200004, '課長の指示が複雑で、理解するのに困っている', NULL, FALSE, 3);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (87200004, '会議に参加したくないので、別の提案を考えている', NULL, FALSE, 4);
INSERT INTO questions (id, user_id, is_system, is_khoa_cu, question_type, content_type, level, selection_type, question, passage, passage_translation, general_explanation, skill_category, base_difficulty, tenant_id, is_active, is_deleted, created_at, created_by) VALUES (87200005, NULL, TRUE, FALSE, 'reading', 'keigo_dokkai_keigo_tong_hop', NULL, 'single', '営業が「特別に対応させていただきたい」と言った最も適切な理由は？
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (87200005, '顧客が営業に対応するよう強制しようとしている', NULL, FALSE, 1);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (87200005, '営業が特別な対応をしたいことを顧客に提案し、許可を求めている', NULL, TRUE, 2);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (87200005, '営業は顧客の要求に全く応じたくない', NULL, FALSE, 3);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (87200005, '過去に同じ対応をさせられたことがある', NULL, FALSE, 4);
INSERT INTO questions (id, user_id, is_system, is_khoa_cu, question_type, content_type, level, selection_type, question, passage, passage_translation, general_explanation, skill_category, base_difficulty, tenant_id, is_active, is_deleted, created_at, created_by) VALUES (87200006, NULL, TRUE, FALSE, 'reading', 'keigo_dokkai_keigo_tong_hop', NULL, 'single', '「金額の値引きをしていただけますか」と「金額の値引きをさせていただけますか」の意味の違いは？
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (87200006, '意味は全く同じで、使い分ける必要がない', NULL, FALSE, 1);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (87200006, '前者は顧客が営業に値引きしてほしいと依頼する；後者は営業が値引きしたいことを顧客に許可を求める', NULL, TRUE, 2);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (87200006, '前者は敬語で、後者は普通語である', NULL, FALSE, 3);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (87200006, '前者は過去形で、後者は未来形である', NULL, FALSE, 4);
INSERT INTO questions (id, user_id, is_system, is_khoa_cu, question_type, content_type, level, selection_type, question, passage, passage_translation, general_explanation, skill_category, base_difficulty, tenant_id, is_active, is_deleted, created_at, created_by) VALUES (87200007, NULL, TRUE, FALSE, 'reading', 'keigo_dokkai_keigo_tong_hop', NULL, 'single', '「金額については、10%の値引きでさせていただく」の表現から、営業の気持ちとして最も正確なものは？
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (87200007, '顧客を支配したいという意図が強い', NULL, FALSE, 1);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (87200007, '10%の値引きが最高だと顧客に強制している', NULL, FALSE, 2);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (87200007, '値引きの提案をする権利と責任を持ち、顧客に敬意を表しながら提供する準備がある', NULL, TRUE, 3);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (87200007, '顧客は強制的に値引きを受けなければならない', NULL, FALSE, 4);
INSERT INTO questions (id, user_id, is_system, is_khoa_cu, question_type, content_type, level, selection_type, question, passage, passage_translation, general_explanation, skill_category, base_difficulty, tenant_id, is_active, is_deleted, created_at, created_by) VALUES (87200008, NULL, TRUE, FALSE, 'reading', 'keigo_dokkai_keigo_tong_hop', NULL, 'single', '全体の通話記録から見ると、顧客と営業の関係において最も正確な説明は？
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (87200008, '顧客は営業に不満を持ち、別の会社に変える準備をしている', NULL, FALSE, 1);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (87200008, '営業は顧客の要求に応じるために、最善の努力をしていて、顧客も合意している', NULL, TRUE, 2);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (87200008, '顧客は営業を完全に支配している', NULL, FALSE, 3);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (87200008, '営業は顧客に逆らい、値引きを拒否している', NULL, FALSE, 4);
INSERT INTO questions (id, user_id, is_system, is_khoa_cu, question_type, content_type, level, selection_type, question, passage, passage_translation, general_explanation, skill_category, base_difficulty, tenant_id, is_active, is_deleted, created_at, created_by) VALUES (87200009, NULL, TRUE, FALSE, 'reading', 'keigo_dokkai_keigo_tong_hop', NULL, 'single', '「外部のコンサルタントに相談させていただき」の表現に見られる、報告者の態度は？
