INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (87200009, '自分たちが外部の専門家に相談することを決定し、その判断を管理者に報告している', NULL, TRUE, 2);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (87200009, 'コンサルタントは必ず相談に応じなければならない', NULL, FALSE, 3);
