INSERT INTO questions (id, user_id, is_system, is_khoa_cu, question_type, content_type, level, selection_type, question, passage, passage_translation, general_explanation, skill_category, base_difficulty, tenant_id, is_active, is_deleted, created_at, created_by) VALUES (87200010, NULL, TRUE, FALSE, 'reading', 'keigo_dokkai_keigo_tong_hop', NULL, 'single', '「改善案に基づいて、チーム内で検討させていただく」の表現において、最も適切な説明は？
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (87200010, 'チームに検討することを強制している', NULL, FALSE, 1);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (87200010, 'チームが改善案を検討することを決定し、それを管理者に報告・許可を求めている', NULL, TRUE, 2);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (87200010, '管理者が検討するよう指示した', NULL, FALSE, 3);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (87200010, '検討は既に完了している', NULL, FALSE, 4);
INSERT INTO questions (id, user_id, is_system, is_khoa_cu, question_type, content_type, level, selection_type, question, passage, passage_translation, general_explanation, skill_category, base_difficulty, tenant_id, is_active, is_deleted, created_at, created_by) VALUES (87200011, NULL, TRUE, FALSE, 'reading', 'keigo_dokkai_keigo_tong_hop', NULL, 'single', '「テスト期間については、管理者の許可を得て、2週間延長させていただきたく存じます」は「2週間延長してもらいたく存じます」に置き換えられますか。その理由は？
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (87200011, 'できない。「させていただく」は報告者（チーム）が延長を実行する主体であり、「してもらう」は管理者が延長を実行する意味だから', NULL, TRUE, 1);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (87200011, 'できる。両方とも同じ意味である', NULL, FALSE, 2);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (87200011, 'できない。「してもらう」はより敬語だから', NULL, FALSE, 3);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (87200011, 'できる。後者のほうが自然である', NULL, FALSE, 4);
INSERT INTO questions (id, user_id, is_system, is_khoa_cu, question_type, content_type, level, selection_type, question, passage, passage_translation, general_explanation, skill_category, base_difficulty, tenant_id, is_active, is_deleted, created_at, created_by) VALUES (87200012, NULL, TRUE, FALSE, 'reading', 'keigo_dokkai_keigo_tong_hop', NULL, 'single', 'この業務報告書から見ると、報告者の目的として最も正確なものは？
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (87200012, '問題点を隠そうとしている', NULL, FALSE, 1);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (87200012, '問題点を認識し、既に対応を開始していることを報告し、その後の管理者の支援や許可を求めている', NULL, TRUE, 2);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (87200012, '管理者に責任を転嫁しようとしている', NULL, FALSE, 3);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (87200012, 'テスト期間を無限に延長したい', NULL, FALSE, 4);
INSERT INTO questions (id, user_id, is_system, is_khoa_cu, question_type, content_type, level, selection_type, question, passage, passage_translation, general_explanation, skill_category, base_difficulty, tenant_id, is_active, is_deleted, created_at, created_by) VALUES (87200013, NULL, TRUE, FALSE, 'reading', 'keigo_dokkai_keigo_tong_hop', NULL, 'single', '田中が「誰か担当させていただける人はいますか」と言った時点での、最も適切な解釈は？
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (87200013, '田中が誰かに担当させる決定をした', NULL, FALSE, 1);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (87200013, '田中がマネージャーを配置する権限を持ち、その配置に関して参加者の同意を求めている', NULL, TRUE, 2);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (87200013, '部下は必ず任務を受け入れなければならない', NULL, FALSE, 3);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (87200013, '田中は決定を放棄し、完全に部下に委ねている', NULL, FALSE, 4);
INSERT INTO questions (id, user_id, is_system, is_khoa_cu, question_type, content_type, level, selection_type, question, passage, passage_translation, general_explanation, skill_category, base_difficulty, tenant_id, is_active, is_deleted, created_at, created_by) VALUES (87200014, NULL, TRUE, FALSE, 'reading', 'keigo_dokkai_keigo_tong_hop', NULL, 'single', '佐藤が「私が担当させてもらえますか」と言ったのに対して、田中が「では、佐藤さんにプロジェクト管理を任させていただきたく思います」と答えた理由として正確なものは？
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (87200014, 'Tanaka không muốn để Satoh quản lý dự án', NULL, FALSE, 1);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (87200014, 'Tanaka có quyền quyết định, nhưng cách nói này thể hiện tôn trọng Satoh và xin cấp trên (nếu có) hoặc những người tham dự họp chấp thuận', NULL, TRUE, 2);
INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (87200014, 'Satoh đã từ chối yêu cầu', NULL, FALSE, 3);
