INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (87200016, 'Tanaka は権限設定をする責任と権限を持ち、それを実行することを約束し、かつ参加者の信頼を求めている', NULL, TRUE, 2);
