INSERT INTO questions (id, user_id, is_system, is_khoa_cu, question_type, content_type, level, selection_type, question, passage, passage_translation, general_explanation, skill_category, base_difficulty, tenant_id, is_active, is_deleted, created_at, created_by) VALUES (87200017, NULL, TRUE, FALSE, 'reading', 'keigo_dokkai_keigo_tong_hop', NULL, 'single', 'FAXで「貴社の新製品を弊社のマーケティングキャンペーンで紹介していただきたく」と書かれた理由として最も適切なものは？
