INSERT INTO questions (id, user_id, is_system, is_khoa_cu, question_type, content_type, level, selection_type, question, passage, passage_translation, general_explanation, skill_category, base_difficulty, tenant_id, is_active, is_deleted, created_at, created_by) VALUES (87200018, NULL, TRUE, FALSE, 'reading', 'keigo_dokkai_keigo_tong_hop', NULL, 'single', 'FAXの「弊社の営業チームに、製品説明の機会をしていただけますか」と、返信メールの「当社が御社の営業チームに詳しく説明させていただくことは可能です」の関係として正確な説明は？
