INSERT INTO questions_answers (question_id, sentence, sentence_translation, is_correct, "order") VALUES (87200018, 'FAXは機会を与えることを要求し、Emailは説明することを提供する。つまり、FAXは一方的な要求だが、Emailは相手の要求に応じながら、自社の条件を追加している', NULL, TRUE, 2);
