💡 もらう → いただく (khi người cho là bề trên). Cặp: もらう/いただく đều là TÔI NHẬN.', 'grammar', 1, 'system', TRUE, FALSE, NOW(), 'system') ON CONFLICT (id) DO UPDATE SET question_type = EXCLUDED.question_type, content_type = EXCLUDED.content_type, level = EXCLUDED.level, question = EXCLUDED.question, passage = EXCLUDED.passage, passage_translation = EXCLUDED.passage_translation, general_explanation = EXCLUDED.general_explanation, skill_category = EXCLUDED.skill_category, base_difficulty = EXCLUDED.base_difficulty, is_active = EXCLUDED.is_active, is_deleted = EXCLUDED.is_deleted, updated_at = NOW(), updated_by = 'system';
