Chủ đề chính của bài báo này là gì?', '8010605', 'Bài báo từ tạp chí ngành về xu hướng chuyển đổi số trong các doanh nghiệp Nhật Bản. Sử dụng bị động trang trọng phức tạp (によって、を通じて、に基づいて) và phân tích sắc thái ngôn ngữ chuyên sâu.', 'Bài báo lập luận rằng do sự thay đổi nhanh chóng của môi trường kinh doanh, các doanh nghiệp cần tái cấu trúc khả năng cạnh tranh của mình qua chuyển đổi số.', 'dokkai', 1, 'system', TRUE, FALSE, NOW(), 'system') ON CONFLICT (id) DO UPDATE SET question_type = EXCLUDED.question_type, content_type = EXCLUDED.content_type, level = EXCLUDED.level, question = EXCLUDED.question, passage = EXCLUDED.passage, passage_translation = EXCLUDED.passage_translation, general_explanation = EXCLUDED.general_explanation, skill_category = EXCLUDED.skill_category, base_difficulty = EXCLUDED.base_difficulty, is_active = EXCLUDED.is_active, is_deleted = EXCLUDED.is_deleted, updated_at = NOW(), updated_by = 'system';
